def _mexc_history_matches(filename: str, fragment: str) -> bool:
    return fragment.casefold() in filename.casefold() and filename.lower().endswith(".xlsx")


def _mexc_collect_source_files(input_dir: Path) -> dict[str, list[Path]]:
    files_by_category = {spec["category"]: [] for spec in _MEXC_HISTORY_SPECS}
    if not input_dir.exists():
        return files_by_category
    for path in sorted(input_dir.rglob("*.xlsx")):
        filename = path.name
        for spec in _MEXC_HISTORY_SPECS:
            if _mexc_history_matches(filename, spec["filename_fragment"]):
                files_by_category[spec["category"]].append(path)
                break
    return files_by_category


def import_mexc_actual_trades(
    *,
    input_dir: Path,
    output_dir: Path | None = None,
    dry_run: bool = False,
) -> dict[str, Any]:
    output_root = output_dir or (BASE_DIR / "logs" / "csv")
    files_by_category = _mexc_collect_source_files(input_dir)
    summary: dict[str, Any] = {
        "input_dir": str(input_dir),
        "output_dir": str(output_root),
        "dry_run": bool(dry_run),
        "categories": {},
        "missing_categories": [],
        "written_files": [],
    }
    normalizers = {
        "trade_history": normalize_mexc_trade_history,
        "order_history": normalize_mexc_order_history,
        "position_history": normalize_mexc_position_history,
    }
    for spec in _MEXC_HISTORY_SPECS:
        category = spec["category"]
        matched_files = files_by_category.get(category, [])
        rows: list[dict[str, str]] = []
        file_summaries: list[dict[str, Any]] = []
        for source_path in matched_files:
            try:
                raw_rows = _xlsx_read_sheet1_rows(source_path)
                normalized_rows = normalizers[category](raw_rows, source_file=source_path.name)
                rows.extend(normalized_rows)
                file_summaries.append(
                    {
                        "source_file": source_path.name,
                        "row_count": len(normalized_rows),
                        "status": "ok",
                    }
                )
            except Exception as exc:  # pragma: no cover - defensive guard
                file_summaries.append(
                    {
                        "source_file": source_path.name,
                        "row_count": 0,
                        "status": f"error:{type(exc).__name__}",
                    }
                )
        output_path = output_root / spec["output_filename"]
        if not dry_run:
            _write_csv_rows(output_path, spec["headers"], rows)
            summary["written_files"].append(output_path.name)
        if not matched_files:
            summary["missing_categories"].append(category)
        summary["categories"][category] = {
            "matched_file_count": len(matched_files),
            "matched_files": [path.name for path in matched_files],
            "row_count": len(rows),
            "status": "missing" if not matched_files else "ok",
            "files": file_summaries,
            "output_file": output_path.name,
        }
    summary["total_rows"] = sum(category_info["row_count"] for category_info in summary["categories"].values())
    return summary


def _mexc_link_normalize_side(value: Any) -> str:
    normalized = str(value or "").strip().lower()
    if normalized in {"buy", "long"}:
        return "long"
    if normalized in {"sell", "short"}:
        return "short"
    if normalized in {"long", "short"}:
        return normalized
    return normalized


def _mexc_link_btc_context(symbol: Any) -> bool:
    normalized = str(symbol or "").strip().replace(" ", "").replace("-", "_").lower()
    if not normalized:
        return True
    return normalized in {"btc", "btc_usdt", "btcusdt"}


def _mexc_link_time_delta_minutes(mail_timestamp: str, trade_opened_at: str) -> float | None:
    mail_dt = _parse_dt(mail_timestamp)
    trade_dt = _parse_dt(trade_opened_at)
    if mail_dt is None or trade_dt is None:
        return None
    if mail_dt.tzinfo is None:
        mail_dt = mail_dt.replace(tzinfo=JST)
    else:
        mail_dt = mail_dt.astimezone(JST)
    if trade_dt.tzinfo is None:
        trade_dt = trade_dt.replace(tzinfo=JST)
    else:
        trade_dt = trade_dt.astimezone(JST)
    return (trade_dt - mail_dt).total_seconds() / 60.0


def _mexc_link_confidence(score: int | None, *, ambiguous: bool = False) -> str:
    if ambiguous or score is None:
        return "ambiguous"
    if score >= 8:
        return "high"
    if score >= 5:
        return "medium"
    if score >= 2:
        return "low"
    return "low"


def _mexc_merge_signal_rows(
    signal_rows: list[dict[str, Any]],
    signal_outcome_rows: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    merged_by_id: dict[str, dict[str, Any]] = {}
    for row in signal_outcome_rows:
        signal_id = str(row.get("signal_id", "")).strip()
        if not signal_id:
            continue
        merged_by_id[signal_id] = dict(row)
    for row in signal_rows:
        signal_id = str(row.get("signal_id", "")).strip()
        if not signal_id:
            continue
        merged = dict(merged_by_id.get(signal_id, {}))
        merged.update(row)
        merged_by_id[signal_id] = merged
    return list(merged_by_id.values())


def score_manual_trade_signal_link(
    trade_row: dict[str, Any],
    signal_row: dict[str, Any],
    *,
    max_after_minutes: int = 240,
) -> dict[str, Any]:
    trade_opened_at = str(trade_row.get("trade_opened_at_jst") or trade_row.get("timestamp_jst", "")).strip()
    mail_timestamp = str(signal_row.get("mail_timestamp_jst") or signal_row.get("timestamp_jst", "")).strip()
    delta_minutes = _mexc_link_time_delta_minutes(mail_timestamp, trade_opened_at)
    actual_side = _mexc_link_normalize_side(trade_row.get("actual_side", trade_row.get("side", "")))
    priority_direction = _mexc_link_normalize_side(signal_row.get("priority_direction", signal_row.get("bias", "")))
    symbol_match = _mexc_link_btc_context(signal_row.get("symbol", ""))
    side_match = bool(actual_side and priority_direction and actual_side == priority_direction)
    if delta_minutes is None or delta_minutes < 0 or delta_minutes > float(max_after_minutes):
        return {
            "eligible": False,
            "actual_side": actual_side,
            "priority_direction": priority_direction,
            "side_match": side_match,
            "time_delta_minutes": delta_minutes,
            "price_context_match": "unknown",
            "link_score": 0,
            "base_score": 0,
            "link_confidence": "ambiguous",
            "link_note": "no_candidate",
            "mail_timestamp_jst": mail_timestamp,
            "trade_opened_at_jst": trade_opened_at,
        }

    time_score = 3 if delta_minutes <= 90 else 1
    link_score = time_score
    if side_match:
        link_score += 3
    if symbol_match:
        link_score += 2
    return {
        "eligible": True,
        "actual_side": actual_side,
        "priority_direction": priority_direction,
        "side_match": side_match,
        "time_delta_minutes": round(delta_minutes, 1),
        "price_context_match": "unknown",
        "link_score": int(link_score),
        "base_score": int(link_score),
        "link_confidence": _mexc_link_confidence(int(link_score)),
        "link_note": "candidate",
        "mail_timestamp_jst": mail_timestamp,
        "trade_opened_at_jst": trade_opened_at,
    }


def build_manual_trade_signal_link_rows(
    *,
    manual_trade_rows: list[dict[str, Any]],
    signal_rows: list[dict[str, Any]],
    signal_outcome_rows: list[dict[str, Any]],
    max_after_minutes: int = 240,
) -> list[dict[str, str]]:
    merged_signals = _mexc_merge_signal_rows(signal_rows, signal_outcome_rows)
    link_rows: list[dict[str, str]] = []
    for trade_row in manual_trade_rows:
        actual_trade_id = str(trade_row.get("actual_trade_id", "")).strip()
        trade_opened_at = str(trade_row.get("trade_opened_at_jst") or trade_row.get("timestamp_jst", "")).strip()
        actual_side = _mexc_link_normalize_side(trade_row.get("actual_side", trade_row.get("side", "")))
        candidates: list[dict[str, Any]] = []
        for signal_row in merged_signals:
            candidate = score_manual_trade_signal_link(trade_row, signal_row, max_after_minutes=max_after_minutes)
            if candidate.get("eligible"):
                candidate = dict(candidate)
                candidate["signal_id"] = str(signal_row.get("signal_id", "")).strip()
                candidates.append(candidate)

        if not candidates:
            link_rows.append(
                {
                    "actual_trade_id": actual_trade_id,
                    "signal_id": "",
                    "mail_timestamp_jst": "",
                    "trade_opened_at_jst": trade_opened_at,
                    "trade_closed_at_jst": "",
                    "actual_side": actual_side,
                    "priority_direction": "",
                    "side_match": "no",
                    "time_delta_minutes": "",
                    "price_context_match": "unknown",
                    "link_score": "0",
                    "link_confidence": "ambiguous",
                    "link_note": "no_candidate",
                }
            )
            continue

        top_score = max(int(candidate["link_score"]) for candidate in candidates)
        top_candidates = [candidate for candidate in candidates if int(candidate["link_score"]) == top_score]
        if len(top_candidates) != 1:
            link_rows.append(
                {
                    "actual_trade_id": actual_trade_id,
                    "signal_id": "",
                    "mail_timestamp_jst": "",
                    "trade_opened_at_jst": trade_opened_at,
                    "trade_closed_at_jst": "",
                    "actual_side": actual_side,
                    "priority_direction": "",
                    "side_match": "no",
                    "time_delta_minutes": "",
                    "price_context_match": "unknown",
                    "link_score": str(top_score),
                    "link_confidence": "ambiguous",
                    "link_note": "competing_candidate_tie",
                }
            )
            continue

        winner = dict(top_candidates[0])
        winner["link_score"] = int(winner["link_score"]) + 1
        winner["link_confidence"] = _mexc_link_confidence(int(winner["link_score"]))
        winner["link_note"] = "matched_unique_top_candidate"
        link_rows.append(
            {
                "actual_trade_id": actual_trade_id,
                "signal_id": str(winner.get("signal_id", "")).strip(),
                "mail_timestamp_jst": str(winner.get("mail_timestamp_jst", "")).strip(),
                "trade_opened_at_jst": trade_opened_at,
                "trade_closed_at_jst": str(trade_row.get("trade_closed_at_jst", "")).strip(),
                "actual_side": actual_side,
                "priority_direction": str(winner.get("priority_direction", "")).strip(),
                "side_match": "yes" if winner.get("side_match") else "no",
                "time_delta_minutes": str(winner.get("time_delta_minutes", "")),
                "price_context_match": str(winner.get("price_context_match", "unknown")).strip() or "unknown",
                "link_score": str(winner["link_score"]),
                "link_confidence": str(winner["link_confidence"]),
                "link_note": str(winner["link_note"]),
            }
        )
    return link_rows


def link_manual_trades_to_signals(
    *,
    manual_trades: Path,
    signals: Path,
    signal_outcomes: Path,
    output_csv: Path | None = None,
    dry_run: bool = False,
    max_after_minutes: int = 240,
) -> dict[str, Any]:
    output_path = output_csv or (BASE_DIR / "logs" / "csv" / "manual_trade_signal_links.csv")
    manual_trade_rows = _load_csv_rows(manual_trades)
    signal_rows = _load_csv_rows(signals)
    signal_outcome_rows = _load_csv_rows(signal_outcomes)
    link_rows = build_manual_trade_signal_link_rows(
        manual_trade_rows=manual_trade_rows,
        signal_rows=signal_rows,
        signal_outcome_rows=signal_outcome_rows,
        max_after_minutes=max_after_minutes,
    )
    if not dry_run:
        _write_csv_rows(output_path, _MEXC_TRADE_SIGNAL_LINK_HEADER, link_rows)

    confidence_counts = Counter(row["link_confidence"] for row in link_rows)
    note_counts = Counter(row["link_note"] for row in link_rows)
    summary = {
        "manual_trades_path": str(manual_trades),
        "signals_path": str(signals),
        "signal_outcomes_path": str(signal_outcomes),
        "output_csv": str(output_path),
        "dry_run": bool(dry_run),
        "max_after_minutes": int(max_after_minutes),
        "manual_trade_count": len(manual_trade_rows),
        "linked_trade_count": sum(1 for row in link_rows if row.get("signal_id")),
        "ambiguous_count": sum(1 for row in link_rows if not row.get("signal_id")),
        "confidence_counts": dict(confidence_counts),
        "note_counts": dict(note_counts),
        "output_row_count": len(link_rows),
        "output_written": not dry_run,
    }
    return summary


def _mexc_trade_side(value: Any) -> str:
    normalized = str(value or "").strip().lower()
    if normalized in {"long", "buy"}:
        return "long"
    if normalized in {"short", "sell"}:
        return "short"
    if normalized in {"unknown", "other"}:
        return "unknown"
    return normalized or "unknown"


def _mexc_parse_decimal(value: Any) -> float | None:
    text = str(value or "").strip()
    if not text:
        return None
    try:
        return float(text)
    except ValueError:
        return None


def _mexc_trade_row_timestamp(row: dict[str, Any]) -> str:
    return str(row.get("timestamp_jst", "")).strip()


def _mexc_rows_latest_timestamp(rows: list[dict[str, Any]], *, keys: tuple[str, ...]) -> str:
    latest: datetime | None = None
    latest_text = ""
    for row in rows:
        for key in keys:
            raw_value = str(row.get(key, "")).strip()
            if not raw_value:
                continue
            parsed = _parse_dt(raw_value)
            if parsed is None:
                continue
            if parsed.tzinfo is None:
                parsed = parsed.replace(tzinfo=JST)
            else:
                parsed = parsed.astimezone(JST)
            if latest is None or parsed > latest:
                latest = parsed
                latest_text = raw_value
    return latest_text


def _mexc_csv_coverage(path: Path) -> dict[str, Any]:
    rows, fieldnames = _load_csv_rows_with_fieldnames(path)
    exists = path.exists()
    status = "missing" if not exists else ("header_only" if not rows else "ok")
    latest_timestamp = _mexc_rows_latest_timestamp(rows, keys=("timestamp_jst", "trade_opened_at_jst", "mail_timestamp_jst"))
    return {
        "path": str(path),
        "exists": exists,
        "status": status,
        "row_count": len(rows),
        "field_count": len(fieldnames),
        "fieldnames": fieldnames,
        "latest_timestamp_jst": latest_timestamp,
    }


def summarize_manual_actual_trade_performance(manual_trade_rows: list[dict[str, Any]]) -> dict[str, Any]:
    side_summaries = {
        "long": {"trade_count": 0, "gross_realized_pnl": 0.0, "net_pnl_after_fee": 0.0, "wins": 0, "losses": 0, "breakeven": 0},
        "short": {"trade_count": 0, "gross_realized_pnl": 0.0, "net_pnl_after_fee": 0.0, "wins": 0, "losses": 0, "breakeven": 0},
        "unknown": {"trade_count": 0, "gross_realized_pnl": 0.0, "net_pnl_after_fee": 0.0, "wins": 0, "losses": 0, "breakeven": 0},
    }
    fee_missing_count = 0
    realized_missing_count = 0
    wins = losses = breakeven = 0
    gross_realized_pnl = 0.0
    net_pnl_after_fee = 0.0
    fee_total = 0.0
    fee_numeric_count = 0
    known_side_count = 0
    for row in manual_trade_rows:
        side = _mexc_trade_side(row.get("side", ""))
        if side in side_summaries:
            side_summaries[side]["trade_count"] += 1
        if side in {"long", "short"}:
            known_side_count += 1
        pnl = _mexc_parse_decimal(row.get("realized_pnl", ""))
        fee = _mexc_parse_decimal(row.get("fee", ""))
        if pnl is None:
            realized_missing_count += 1
            continue
        gross_realized_pnl += pnl
        if fee is None:
            fee_missing_count += 1
            net_pnl_after_fee += pnl
        else:
            fee_numeric_count += 1
            fee_total += fee
            net_pnl_after_fee += pnl - abs(fee)
        if pnl > 0:
            wins += 1
            side_summaries[side]["wins"] += 1
        elif pnl < 0:
            losses += 1
            side_summaries[side]["losses"] += 1
        else:
            breakeven += 1
            side_summaries[side]["breakeven"] += 1
        side_summaries[side]["gross_realized_pnl"] += pnl
        side_summaries[side]["net_pnl_after_fee"] += pnl - abs(fee) if fee is not None else pnl

    total_numeric = wins + losses + breakeven
    win_rate = round((wins / total_numeric) if total_numeric else 0.0, 4)
    side_output = {}
    for side, data in side_summaries.items():
        side_total = data["wins"] + data["losses"] + data["breakeven"]
        side_output[side] = {
            "trade_count": data["trade_count"],
            "gross_realized_pnl": round(data["gross_realized_pnl"], 8),
            "net_pnl_after_fee": round(data["net_pnl_after_fee"], 8),
            "wins": data["wins"],
            "losses": data["losses"],
            "breakeven": data["breakeven"],
            "win_rate": round((data["wins"] / side_total) if side_total else 0.0, 4),
        }
    return {
        "total_actual_trades": len(manual_trade_rows),
        "known_side_trade_count": known_side_count,
        "side_counts": {side: data["trade_count"] for side, data in side_output.items()},
        "gross_realized_pnl": round(gross_realized_pnl, 8),
        "net_pnl_after_fee": round(net_pnl_after_fee, 8),
        "fee_total": round(fee_total, 8),
        "fee_numeric_count": fee_numeric_count,
        "fee_missing_count": fee_missing_count,
        "realized_missing_count": realized_missing_count,
        "wins": wins,
        "losses": losses,
        "breakeven": breakeven,
        "win_rate": win_rate,
        "side_summaries": side_output,
    }


def summarize_manual_trade_link_quality(link_rows: list[dict[str, Any]]) -> dict[str, Any]:
    confidence_counts = Counter(str(row.get("link_confidence", "")).strip() or "unknown" for row in link_rows)
    note_counts = Counter(str(row.get("link_note", "")).strip() or "unknown" for row in link_rows)
    side_match_counts = Counter(
        "unknown"
        if str(row.get("side_match", "")).strip() not in {"yes", "no"}
        else ("true" if str(row.get("side_match", "")).strip() == "yes" else "false")
        for row in link_rows
    )
    high_or_medium = confidence_counts.get("high", 0) + confidence_counts.get("medium", 0)
    total = len(link_rows)
    return {
        "total_link_rows": total,
        "linked_rows": sum(1 for row in link_rows if str(row.get("signal_id", "")).strip()),
        "confidence_counts": dict(confidence_counts),
        "note_counts": dict(note_counts),
        "side_match_counts": dict(side_match_counts),
        "high_or_medium_link_rate": round((high_or_medium / total) if total else 0.0, 4),
        "no_candidate_count": note_counts.get("no_candidate", 0),
        "competing_candidate_tie_count": note_counts.get("competing_candidate_tie", 0),
        "ambiguous_count": confidence_counts.get("ambiguous", 0),
    }


def calibrate_manual_trade_proxy_vs_actual(
    manual_trade_rows: list[dict[str, Any]],
    link_rows: list[dict[str, Any]],
    signal_outcome_rows: list[dict[str, Any]],
) -> dict[str, Any]:
    trade_map = {str(row.get("actual_trade_id", "")).strip(): row for row in manual_trade_rows if str(row.get("actual_trade_id", "")).strip()}
    link_map = {str(row.get("actual_trade_id", "")).strip(): row for row in link_rows if str(row.get("actual_trade_id", "")).strip()}
    outcome_map = {str(row.get("signal_id", "")).strip(): row for row in signal_outcome_rows if str(row.get("signal_id", "")).strip()}
    buckets = Counter(
        {
            "manual_edge_confirmed": 0,
            "proxy_too_aggressive": 0,
            "proxy_too_pessimistic": 0,
            "direction_mismatch_loss": 0,
            "ambiguous_needs_review": 0,
            "insufficient_data": 0,
        }
    )
    details: list[dict[str, str]] = []

    def _is_watch_like(text: str) -> bool:
        normalized = text.upper()
        return any(term in normalized for term in ("NO_TRADE", "WATCH", "SKIP", "WAIT"))

    for actual_trade_id, trade_row in trade_map.items():
        link_row = link_map.get(actual_trade_id)
        pnl = _mexc_parse_decimal(trade_row.get("realized_pnl", ""))
        if pnl is None or link_row is None or not str(link_row.get("actual_trade_id", "")).strip():
            buckets["insufficient_data"] += 1
            details.append({"actual_trade_id": actual_trade_id, "bucket": "insufficient_data"})
            continue
        signal_id = str(link_row.get("signal_id", "")).strip()
        confidence = str(link_row.get("link_confidence", "")).strip()
        side_match = str(link_row.get("side_match", "")).strip().lower() == "yes"
        if confidence == "ambiguous" or not signal_id:
            buckets["ambiguous_needs_review"] += 1
            details.append({"actual_trade_id": actual_trade_id, "bucket": "ambiguous_needs_review"})
            continue
        if confidence not in {"high", "medium"}:
            buckets["ambiguous_needs_review"] += 1
            details.append({"actual_trade_id": actual_trade_id, "bucket": "ambiguous_needs_review"})
            continue

        outcome_row = outcome_map.get(signal_id, {})
        prelabel_text = " ".join(
            str(outcome_row.get(field, "")).strip()
            for field in ("prelabel", "prelabel_primary_reason", "signal_tier")
        ).strip()
        if side_match and pnl > 0:
            if _is_watch_like(prelabel_text):
                buckets["proxy_too_pessimistic"] += 1
                details.append({"actual_trade_id": actual_trade_id, "bucket": "proxy_too_pessimistic"})
            else:
                buckets["manual_edge_confirmed"] += 1
                details.append({"actual_trade_id": actual_trade_id, "bucket": "manual_edge_confirmed"})
            continue
        if side_match and pnl < 0:
            buckets["proxy_too_aggressive"] += 1
            details.append({"actual_trade_id": actual_trade_id, "bucket": "proxy_too_aggressive"})
            continue
        if not side_match and pnl < 0:
            buckets["direction_mismatch_loss"] += 1
            details.append({"actual_trade_id": actual_trade_id, "bucket": "direction_mismatch_loss"})
            continue
        if _is_watch_like(prelabel_text) and pnl > 0:
            buckets["proxy_too_pessimistic"] += 1
            details.append({"actual_trade_id": actual_trade_id, "bucket": "proxy_too_pessimistic"})
            continue
        buckets["ambiguous_needs_review"] += 1
        details.append({"actual_trade_id": actual_trade_id, "bucket": "ambiguous_needs_review"})

    return {
        "calibration_counts": dict(buckets),
        "calibration_details": details,
    }


def _manual_trade_ground_truth_recommendation_codes(
    *,
    trade_summary: dict[str, Any],
    link_summary: dict[str, Any],
    calibration_summary: dict[str, Any],
) -> list[str]:
    codes: list[str] = []
    total_trades = int(trade_summary.get("total_actual_trades", 0))
    if total_trades <= 0 or trade_summary.get("realized_missing_count", 0):
        codes.append("INSUFFICIENT_GROUND_TRUTH_DATA")
    if trade_summary.get("fee_missing_count", 0) > 0:
        codes.append("FEE_COVERAGE_REVIEW")
    if link_summary.get("high_or_medium_link_rate", 0.0) < 0.8 or link_summary.get("ambiguous_count", 0) > 0:
        codes.append("LINKAGE_COVERAGE_REVIEW")
    if link_summary.get("ambiguous_count", 0) > 0 or link_summary.get("no_candidate_count", 0) > 0 or link_summary.get("competing_candidate_tie_count", 0) > 0:
        codes.append("AMBIGUOUS_LINK_MANUAL_REVIEW")
    if trade_summary.get("side_counts", {}).get("long", 0) > 0 and trade_summary.get("side_counts", {}).get("short", 0) > 0:
        long_net = trade_summary["side_summaries"]["long"]["net_pnl_after_fee"]
        short_net = trade_summary["side_summaries"]["short"]["net_pnl_after_fee"]
        long_count = trade_summary["side_summaries"]["long"]["trade_count"]
        short_count = trade_summary["side_summaries"]["short"]["trade_count"]
        if long_count and short_count and abs(long_net - short_net) >= 5:
            codes.append("LONG_SHORT_ACTUAL_BALANCE_REVIEW")
    calibration_counts = calibration_summary.get("calibration_counts", {})
    if calibration_counts.get("proxy_too_aggressive", 0) > calibration_counts.get("proxy_too_pessimistic", 0) and calibration_counts.get("proxy_too_aggressive", 0) > 0:
        codes.append("PROXY_TOO_AGGRESSIVE_REVIEW")
    elif calibration_counts.get("proxy_too_pessimistic", 0) > calibration_counts.get("proxy_too_aggressive", 0) and calibration_counts.get("proxy_too_pessimistic", 0) > 0:
        codes.append("PROXY_TOO_PESSIMISTIC_REVIEW")
    if not codes:
        codes.append("INSUFFICIENT_GROUND_TRUTH_DATA")
    seen: set[str] = set()
    deduped: list[str] = []
    for code in codes:
        if code not in seen:
            seen.add(code)
            deduped.append(code)
    return deduped


def build_manual_trade_ground_truth_report(
    *,
    base_dir: Path = BASE_DIR,
    manual_trades: Path | None = None,
    links: Path | None = None,
    signal_outcomes: Path | None = None,
    output_md: Path | None = None,
    report_date: str | None = None,
    dry_run: bool = False,
) -> tuple[str, dict[str, Any]]:
    manual_trades_path = manual_trades or base_dir / "logs" / "csv" / "manual_actual_trades.csv"
    links_path = links or base_dir / "logs" / "csv" / "manual_trade_signal_links.csv"
    signal_outcomes_path = signal_outcomes or base_dir / "logs" / "csv" / "signal_outcomes.csv"

    manual_trade_rows = _load_csv_rows(manual_trades_path)
    link_rows = _load_csv_rows(links_path)
    signal_outcome_rows = _load_csv_rows(signal_outcomes_path)

    trade_summary = summarize_manual_actual_trade_performance(manual_trade_rows)
    link_summary = summarize_manual_trade_link_quality(link_rows)
    calibration_summary = calibrate_manual_trade_proxy_vs_actual(manual_trade_rows, link_rows, signal_outcome_rows)

    inferred_report_date = str(report_date or "").strip()
    if not inferred_report_date:
        latest_timestamp = _mexc_rows_latest_timestamp(manual_trade_rows, keys=("timestamp_jst",))
        if latest_timestamp:
            parsed = _parse_dt(latest_timestamp)
            if parsed is not None:
                inferred_report_date = (parsed.astimezone(JST) if parsed.tzinfo else parsed.replace(tzinfo=JST)).strftime("%Y%m%d")
    if not inferred_report_date:
        inferred_report_date = datetime.now(tz=JST).strftime("%Y%m%d")

    report_path = output_md or (base_dir / _MEXC_GROUND_TRUTH_REPORT_OUTPUT_DIR / f"manual_trade_ground_truth_{inferred_report_date}.md")
    coverage = {
        "manual_trades": _mexc_csv_coverage(manual_trades_path),
        "links": _mexc_csv_coverage(links_path),
        "signal_outcomes": _mexc_csv_coverage(signal_outcomes_path),
    }
    recommendation_codes = _manual_trade_ground_truth_recommendation_codes(
        trade_summary=trade_summary,
        link_summary=link_summary,
        calibration_summary=calibration_summary,
    )

    lines = [
        _MEXC_GROUND_TRUTH_REPORT_HEADER,
        "",
        "## 1. Purpose Fit Summary",
        "- report-only",
        "- not FORMAL_GO",
        "- no automatic order",
        "- no private/account/order endpoints",
        "- human decides manually",
        "- MEXC actual trade history is treated as local calibration evidence, not as strategy proof",
        "",
        "## 2. Input Coverage",
    ]
    for name, item in coverage.items():
        lines.append(
            f"- {name}: status={item['status']} / rows={item['row_count']} / fields={item['field_count']}"
            + (f" / latest_timestamp_jst={item['latest_timestamp_jst']}" if item["latest_timestamp_jst"] else "")
        )
    lines.append("")
    lines.extend(
        [
            "## 3. Actual Trade Summary",
            f"- total_actual_trades: {trade_summary['total_actual_trades']}",
            f"- side_counts: long={trade_summary['side_counts']['long']}, short={trade_summary['side_counts']['short']}, unknown={trade_summary['side_counts']['unknown']}",
            f"- gross_realized_pnl: {trade_summary['gross_realized_pnl']:.4f}",
            f"- fee_total: {trade_summary['fee_total']:.4f}",
            f"- net_pnl_after_fee: {trade_summary['net_pnl_after_fee']:.4f}",
            f"- wins={trade_summary['wins']}, losses={trade_summary['losses']}, breakeven={trade_summary['breakeven']}, win_rate={trade_summary['win_rate']:.4f}",
            f"- fee_coverage: {trade_summary['fee_numeric_count']}/{trade_summary['total_actual_trades']} numeric",
        ]
    )
    if trade_summary["fee_missing_count"]:
        lines.append(f"- fee coverage is incomplete: missing_or_invalid_fee_rows={trade_summary['fee_missing_count']}")
    if trade_summary["realized_missing_count"]:
        lines.append(f"- realized_pnl coverage is incomplete: missing_or_invalid_rows={trade_summary['realized_missing_count']}")
    lines.append("")
    lines.extend(
        [
            "## 4. Actual Manual Short Performance",
            f"- trade_count: {trade_summary['side_summaries']['short']['trade_count']}",
            f"- gross_realized_pnl: {trade_summary['side_summaries']['short']['gross_realized_pnl']:.4f}",
            f"- net_pnl_after_fee: {trade_summary['side_summaries']['short']['net_pnl_after_fee']:.4f}",
            f"- wins={trade_summary['side_summaries']['short']['wins']}, losses={trade_summary['side_summaries']['short']['losses']}, breakeven={trade_summary['side_summaries']['short']['breakeven']}, win_rate={trade_summary['side_summaries']['short']['win_rate']:.4f}",
            "",
            "## 5. Actual Manual Long Performance",
            f"- trade_count: {trade_summary['side_summaries']['long']['trade_count']}",
            f"- gross_realized_pnl: {trade_summary['side_summaries']['long']['gross_realized_pnl']:.4f}",
            f"- net_pnl_after_fee: {trade_summary['side_summaries']['long']['net_pnl_after_fee']:.4f}",
            f"- wins={trade_summary['side_summaries']['long']['wins']}, losses={trade_summary['side_summaries']['long']['losses']}, breakeven={trade_summary['side_summaries']['long']['breakeven']}, win_rate={trade_summary['side_summaries']['long']['win_rate']:.4f}",
            "",
            "## 6. Signal Linkage Quality",
            f"- total_link_rows: {link_summary['total_link_rows']}",
            f"- linked_rows: {link_summary['linked_rows']}",
            f"- confidence_counts: high={link_summary['confidence_counts'].get('high', 0)}, medium={link_summary['confidence_counts'].get('medium', 0)}, low={link_summary['confidence_counts'].get('low', 0)}, ambiguous={link_summary['confidence_counts'].get('ambiguous', 0)}",
            f"- no_candidate_count: {link_summary['no_candidate_count']}",
            f"- competing_candidate_tie_count: {link_summary['competing_candidate_tie_count']}",
            f"- side_match_counts: true={link_summary['side_match_counts'].get('true', 0)}, false={link_summary['side_match_counts'].get('false', 0)}, unknown={link_summary['side_match_counts'].get('unknown', 0)}",
            f"- high_or_medium_link_rate: {link_summary['high_or_medium_link_rate']:.4f}",
            "",
            "## 7. Proxy-vs-Actual Calibration",
        ]
    )
    for key in (
        "manual_edge_confirmed",
        "proxy_too_aggressive",
        "proxy_too_pessimistic",
        "direction_mismatch_loss",
        "ambiguous_needs_review",
        "insufficient_data",
    ):
        lines.append(f"- {key}: {calibration_summary['calibration_counts'].get(key, 0)}")
    lines.extend(
        [
            "",
            "## 8. Confirmed Improvement Candidates",
        ]
    )
    if recommendation_codes:
        for code in recommendation_codes:
            lines.append(f"- {code}: candidate for review, evidence so far only, manual confirmation required")
    else:
        lines.append("- INSUFFICIENT_GROUND_TRUTH_DATA: candidate for review, evidence so far only, manual confirmation required")
    lines.extend(
        [
            "",
            "## 9. Next 2-Week Action Plan",
            "- Review ambiguous links first, then compare high/medium linked trades against proxy labels.",
            "- Separate long and short evidence before adjusting any proxy thresholds.",
            "- Re-run this report after the next importer/linker batch to check whether calibration moves in a stable direction.",
            "",
            "## 10. Safety Boundary",
            f"- {_MEXC_GROUND_TRUTH_REPORT_SAFETY_BOUNDARY}",
            "",
            "## 11. Limitations",
        ]
    )
    limitations: list[str] = []
    if coverage["manual_trades"]["status"] != "ok":
        limitations.append("manual_actual_trades input is missing or header-only")
    if coverage["links"]["status"] != "ok":
        limitations.append("manual_trade_signal_links input is missing or header-only")
    if coverage["signal_outcomes"]["status"] != "ok":
        limitations.append("signal_outcomes input is missing or header-only")
    if trade_summary["realized_missing_count"]:
        limitations.append("some realized_pnl values are missing or invalid")
    if trade_summary["fee_missing_count"]:
        limitations.append("fee coverage is incomplete")
    if link_summary["ambiguous_count"] or link_summary["no_candidate_count"] or link_summary["competing_candidate_tie_count"]:
        limitations.append("ambiguous links remain and require manual review")
    if not limitations:
        limitations.append("no major structural limitation was detected, but this remains descriptive historical evidence only")
    for item in limitations:
        lines.append(f"- {item}")

    report = "\n".join(lines) + "\n"
    if not dry_run:
        _ensure_parent(report_path)
        report_path.write_text(report, encoding="utf-8")
    payload = {
        "schema_version": "manual_trade_ground_truth.v1",
        "report_date": inferred_report_date,
        "report_path": str(report_path),
        "input_counts": {name: {"status": item["status"], "rows": item["row_count"], "fields": item["field_count"]} for name, item in coverage.items()},
        "total_actual_trades": trade_summary["total_actual_trades"],
        "gross_realized_pnl": trade_summary["gross_realized_pnl"],
        "net_pnl_after_fee": trade_summary["net_pnl_after_fee"],
        "win_rate": trade_summary["win_rate"],
        "link_confidence_counts": link_summary["confidence_counts"],
        "calibration_counts": calibration_summary["calibration_counts"],
        "recommendation_codes": recommendation_codes,
        "safety_boundary": _MEXC_GROUND_TRUTH_REPORT_SAFETY_BOUNDARY,
    }
    return report, payload


def _post_eval_normalize_text(value: Any) -> str:
    return str(value or "").strip().lower()


def _post_eval_contains_any(value: Any, needles: tuple[str, ...]) -> bool:
    haystack = _post_eval_normalize_text(value)
    if not haystack:
        return False
    return any(needle in haystack for needle in needles)


def _post_eval_watch_like(value: Any) -> bool:
    haystack = str(value or "").strip().lower()
    if not haystack:
        return False
    return any(
        needle in haystack
        for needle in (
            "no_trade",
            "no trade",
            "watch",
            "skip",
            "wait",
            "見送り",
            "様子見",
        )
    )


def _post_eval_defensive_subject(value: Any) -> bool:
    haystack = str(value or "").strip().lower()
    if not haystack:
        return False
    return any(
        needle in haystack
        for needle in (
            "売買非推奨",
            "実弾不可",
            "見送り",
            "no trade",
            "no_trade",
            "skip",
            "様子見",
            "慎重",
            "defensive",
        )
    )


def _post_eval_positive_proxy_outcome(row: dict[str, Any]) -> bool:
    positive_string_tokens = (
        "positive",
        "profit",
        "win",
        "good",
        "correct",
        "success",
        "entry_ok",
        "tp1_hit_first",
        "tp2_hit_first",
        "target_hit",
        "long_win",
        "short_win",
    )
    for field in (
        "outcome",
        "direction_outcome",
        "candidate_result_12h",
        "candidate_result_24h",
        "signal_based_outcome",
        "user_verdict",
        "prelabel",
    ):
        if _post_eval_contains_any(row.get(field, ""), positive_string_tokens):
            return True
    for field in (
        "actual_pnl",
        "gross_realized_pnl",
        "net_pnl_after_fee",
        "realized_pnl",
        "candidate_delta_12h",
        "candidate_delta_24h",
        "signal_based_MFE_24h",
    ):
        value = _mexc_parse_decimal(row.get(field, ""))
        if value is not None and value > 0:
            return True
    return False


def _post_eval_row_side(row: dict[str, Any]) -> str:
    side = str(row.get("side", "")).strip().lower()
    if not side:
        side = str(row.get("bias", "")).strip().lower()
    if not side:
        side = str(row.get("direction", "")).strip().lower()
    if side in {"long", "buy"}:
        return "long"
    if side in {"short", "sell"}:
        return "short"
    return side or "unknown"


def _post_eval_bool_like(value: Any) -> bool | None:
    text = str(value or "").strip().lower()
    if text in {"true", "1", "yes", "on"}:
        return True
    if text in {"false", "0", "no", "off"}:
        return False
    return None


def _post_eval_input_coverage(path: Path, *, timestamp_keys: tuple[str, ...]) -> dict[str, Any]:
    rows, fieldnames = _load_csv_rows_with_fieldnames(path)
    exists = path.exists()
    status = "missing" if not exists else ("header_only" if not rows else "ok")
    latest_timestamp = _mexc_rows_latest_timestamp(rows, keys=timestamp_keys) if rows else ""
    return {
        "path": str(path),
        "exists": exists,
        "status": status,
        "row_count": len(rows),
        "field_count": len(fieldnames),
        "fieldnames": fieldnames,
        "latest_timestamp_jst": latest_timestamp,
        "rows": rows,
    }


def _post_eval_candidate_id(report_date: str, code: str, evidence_summary: str, evidence_score: int, rank: int) -> str:
    return f"rec_{_mexc_hash_text('post_eval', report_date, code, evidence_summary, str(evidence_score), str(rank))}"


def _post_eval_candidate_row(
    *,
    report_date: str,
    code: str,
    evidence_score: int,
    affected_area: str,
    proposed_action: str,
    evidence_summary: str,
    required_human_approval: bool = True,
    safety_note: str = _POST_EVAL_RECOMMENDATION_SAFETY_BOUNDARY,
    confidence: str = "proxy_backed",
    priority: str = "low",
    proxy_evidence_count: int = 0,
    actual_backed_count: int = 0,
    high_link_count: int = 0,
    medium_link_count: int = 0,
) -> dict[str, Any]:
    return {
        "recommendation_code": code,
        "evidence_score": int(evidence_score),
        "affected_area": affected_area,
        "proposed_action": proposed_action,
        "evidence_summary": evidence_summary,
        "required_human_approval": "true" if required_human_approval else "false",
        "safety_note": safety_note,
        "confidence": confidence,
        "priority": priority,
        "proxy_evidence_count": int(proxy_evidence_count),
        "actual_backed_count": int(actual_backed_count),
        "high_link_count": int(high_link_count),
        "medium_link_count": int(medium_link_count),
        "_report_date": report_date,
    }


def _post_eval_priority_from_score(score: int) -> str:
    if score >= 8:
        return "high"
    if score >= 4:
        return "medium"
    return "low"


def _post_eval_confidence_from_candidate(candidate: dict[str, Any]) -> str:
    if candidate.get("confidence") == "insufficient":
        return "insufficient"
    if int(candidate.get("actual_backed_count", 0)) > 0:
        return "actual_backed"
    return "proxy_backed"


def _post_eval_candidate_sort_key(row: dict[str, Any]) -> tuple[int, int, int, str]:
    confidence_order = {"actual_backed": 0, "proxy_backed": 1, "insufficient": 2}
    return (
        -int(row.get("evidence_score", 0)),
        confidence_order.get(str(row.get("confidence", "proxy_backed")), 9),
        -int(row.get("actual_backed_count", 0)),
        str(row.get("recommendation_code", "")).strip(),
    )


def build_post_eval_recommendation_candidates(
    *,
    base_dir: Path = BASE_DIR,
    signal_outcomes: Path | None = None,
    active_plan_candidate_outcomes: Path | None = None,
    active_plan_candidate_intraperiod_outcomes: Path | None = None,
    user_reviews: Path | None = None,
    manual_trades: Path | None = None,
    links: Path | None = None,
    report_date: str | None = None,
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    signal_outcomes_path = signal_outcomes or base_dir / "logs" / "csv" / "signal_outcomes.csv"
    active_plan_candidate_outcomes_path = active_plan_candidate_outcomes or base_dir / "logs" / "csv" / "active_plan_candidate_outcomes.csv"
    active_plan_candidate_intraperiod_outcomes_path = active_plan_candidate_intraperiod_outcomes or base_dir / "logs" / "csv" / "active_plan_candidate_intraperiod_outcomes.csv"
    user_reviews_path = user_reviews or base_dir / "logs" / "csv" / "user_reviews.csv"
    manual_trades_path = manual_trades or base_dir / "logs" / "csv" / "manual_actual_trades.csv"
    links_path = links or base_dir / "logs" / "csv" / "manual_trade_signal_links.csv"

    coverage = {
        "signal_outcomes": _post_eval_input_coverage(signal_outcomes_path, timestamp_keys=("timestamp_jst", "mail_timestamp_jst")),
        "active_plan_candidate_outcomes": _post_eval_input_coverage(active_plan_candidate_outcomes_path, timestamp_keys=("timestamp_jst",)),
        "active_plan_candidate_intraperiod_outcomes": _post_eval_input_coverage(active_plan_candidate_intraperiod_outcomes_path, timestamp_keys=("timestamp_jst",)),
        "user_reviews": _post_eval_input_coverage(user_reviews_path, timestamp_keys=("timestamp_jst",)),
        "manual_trades": _post_eval_input_coverage(manual_trades_path, timestamp_keys=("timestamp_jst",)),
        "links": _post_eval_input_coverage(links_path, timestamp_keys=("mail_timestamp_jst", "trade_opened_at_jst", "trade_closed_at_jst")),
    }

    all_latest_candidates: list[str] = []
    for item in coverage.values():
        latest = str(item.get("latest_timestamp_jst", "")).strip()
        if latest:
            all_latest_candidates.append(latest)
    inferred_report_date = str(report_date or "").strip()
    if not inferred_report_date and all_latest_candidates:
        parsed_latest = [dt for dt in (_parse_dt(value) for value in all_latest_candidates) if dt is not None]
        if parsed_latest:
            latest_dt = max(
                dt.astimezone(JST) if dt.tzinfo else dt.replace(tzinfo=JST)
                for dt in parsed_latest
            )
            inferred_report_date = latest_dt.strftime("%Y%m%d")
    if not inferred_report_date:
        inferred_report_date = datetime.now(tz=JST).strftime("%Y%m%d")

    signal_rows = coverage["signal_outcomes"]["rows"]
    active_plan_candidate_outcomes_rows = coverage["active_plan_candidate_outcomes"]["rows"]
    active_plan_candidate_intraperiod_outcomes_rows = coverage["active_plan_candidate_intraperiod_outcomes"]["rows"]
    user_review_rows = coverage["user_reviews"]["rows"]
    manual_trade_rows = coverage["manual_trades"]["rows"]
    link_rows = coverage["links"]["rows"]

    trade_summary = summarize_manual_actual_trade_performance(manual_trade_rows)
    link_summary = summarize_manual_trade_link_quality(link_rows)
    calibration_summary = calibrate_manual_trade_proxy_vs_actual(manual_trade_rows, link_rows, signal_rows)

    signal_watch_positive_rows = [
        row
        for row in signal_rows
        if _post_eval_watch_like(row.get("prelabel", "")) and _post_eval_positive_proxy_outcome(row)
    ]
    defensive_review_rows = [
        row for row in user_review_rows if _post_eval_defensive_subject(" ".join(str(row.get(field, "")) for field in ("subject", "title", "body")))
    ]
    balance_rows = active_plan_candidate_outcomes_rows + active_plan_candidate_intraperiod_outcomes_rows
    balance_long_count = sum(1 for row in balance_rows if _post_eval_row_side(row) == "long")
    balance_short_count = sum(1 for row in balance_rows if _post_eval_row_side(row) == "short")
    balance_total = balance_long_count + balance_short_count
    balance_imbalance_rate = round((abs(balance_long_count - balance_short_count) / balance_total) if balance_total else 0.0, 4)

    turning_rows = []
    for row in active_plan_candidate_intraperiod_outcomes_rows:
        row_text = " ".join(
            str(row.get(field, "")).strip()
            for field in (
                "candidate_type",
                "active_primary_action",
                "prelabel",
                "notes",
                "first_exit_reason",
            )
        )
        if not any(token in row_text.lower() for token in ("turn", "counter", "reversal", "反転", "反発", "戻し")):
            continue
        sl_first = _post_eval_bool_like(row.get("sl_first", ""))
        mae_r = _mexc_parse_decimal(row.get("mae_r", ""))
        if sl_first is True or (mae_r is not None and mae_r >= 1.0):
            turning_rows.append(row)

    high_link_count = sum(
        1
        for row in link_rows
        if str(row.get("link_confidence", "")).strip() == "high" and str(row.get("signal_id", "")).strip()
    )
    medium_link_count = sum(
        1
        for row in link_rows
        if str(row.get("link_confidence", "")).strip() == "medium" and str(row.get("signal_id", "")).strip()
    )
    positive_actual_link_count = sum(
        1
        for trade_row in manual_trade_rows
        if (_mexc_parse_decimal(trade_row.get("realized_pnl", "")) or 0.0) > 0
    )
    actual_backed_link_count = sum(
        1
        for trade_row in manual_trade_rows
        if str(trade_row.get("actual_trade_id", "")).strip()
        and str(
            next(
                (row for row in link_rows if str(row.get("actual_trade_id", "")).strip() == str(trade_row.get("actual_trade_id", "")).strip()),
                {},
            ).get("link_confidence", "")
        ).strip()
        in {"high", "medium"}
    )
    actual_backed_trade_ids = {
        str(trade_row.get("actual_trade_id", "")).strip()
        for trade_row in manual_trade_rows
        if str(trade_row.get("actual_trade_id", "")).strip()
        and str(
            next(
                (row for row in link_rows if str(row.get("actual_trade_id", "")).strip() == str(trade_row.get("actual_trade_id", "")).strip()),
                {},
            ).get("link_confidence", "")
        ).strip()
        in {"high", "medium"}
    }
    coverage_complete = all(item["status"] == "ok" for item in coverage.values())

    candidates: list[dict[str, Any]] = []

    if coverage_complete and signal_watch_positive_rows:
        candidates.append(
            _post_eval_candidate_row(
                report_date=inferred_report_date,
                code="NO_TRADE_SPLIT_REVIEW",
                evidence_score=len(signal_watch_positive_rows),
                affected_area="signal prelabel / no-trade split",
                proposed_action="review NO_TRADE split candidate",
                evidence_summary=(
                    f"{len(signal_watch_positive_rows)} signal_outcomes rows had NO_TRADE/WATCH/SKIP-like wording with positive proxy evidence"
                ),
                confidence="proxy_backed",
                proxy_evidence_count=len(signal_watch_positive_rows),
            )
        )

    if coverage_complete and defensive_review_rows:
        candidates.append(
            _post_eval_candidate_row(
                report_date=inferred_report_date,
                code="SUBJECT_DEFENSIVE_WORDING_REVIEW",
                evidence_score=len(defensive_review_rows),
                affected_area="user review subject wording",
                proposed_action="review subject wording candidate",
                evidence_summary=f"{len(defensive_review_rows)} user_reviews subjects looked defensive or skip-like",
                confidence="proxy_backed",
                proxy_evidence_count=len(defensive_review_rows),
            )
        )

    if coverage_complete and balance_total >= 4 and balance_imbalance_rate >= 0.4:
        imbalance_side = "long" if balance_long_count > balance_short_count else "short"
        candidates.append(
            _post_eval_candidate_row(
                report_date=inferred_report_date,
                code="LONG_SHORT_BALANCE_REVIEW",
                evidence_score=abs(balance_long_count - balance_short_count),
                affected_area="active-plan long/short weighting",
                proposed_action="review long/short display weighting candidate",
                evidence_summary=(
                    f"active plan rows show imbalance long={balance_long_count}, short={balance_short_count}, "
                    f"dominant_side={imbalance_side}, imbalance_rate={balance_imbalance_rate:.2f}"
                ),
                confidence="proxy_backed",
                proxy_evidence_count=abs(balance_long_count - balance_short_count),
            )
        )

    if coverage_complete and turning_rows:
        candidates.append(
            _post_eval_candidate_row(
                report_date=inferred_report_date,
                code="TURNING_BRAKE_REVIEW",
                evidence_score=len(turning_rows),
                affected_area="turning / counter wording and rank",
                proposed_action="review turning brake wording/rank candidate",
                evidence_summary=(
                    f"{len(turning_rows)} intraperiod rows had turning/counter style wording with sl_first or high mae_r evidence"
                ),
                confidence="proxy_backed",
                proxy_evidence_count=len(turning_rows),
            )
        )

    if coverage_complete and calibration_summary["calibration_counts"].get("proxy_too_aggressive", 0) > 0:
        aggressive_rows = []
        link_map = {str(row.get("actual_trade_id", "")).strip(): row for row in link_rows if str(row.get("actual_trade_id", "")).strip()}
        signal_map = {str(row.get("signal_id", "")).strip(): row for row in signal_rows if str(row.get("signal_id", "")).strip()}
        for trade_row in manual_trade_rows:
            actual_trade_id = str(trade_row.get("actual_trade_id", "")).strip()
            pnl = _mexc_parse_decimal(trade_row.get("realized_pnl", ""))
            if pnl is None or pnl >= 0:
                continue
            link_row = link_map.get(actual_trade_id, {})
            if str(link_row.get("link_confidence", "")).strip() not in {"high", "medium"}:
                continue
            if str(link_row.get("side_match", "")).strip().lower() != "yes":
                continue
            aggressive_rows.append((trade_row, link_row, signal_map.get(str(link_row.get("signal_id", "")).strip(), {})))
        if aggressive_rows:
            candidates.append(
                _post_eval_candidate_row(
                    report_date=inferred_report_date,
                    code="PROXY_TOO_AGGRESSIVE_REVIEW",
                    evidence_score=len(aggressive_rows),
                    affected_area="proxy label aggressiveness",
                    proposed_action="review proxy aggressiveness candidate",
                    evidence_summary=(
                        f"{len(aggressive_rows)} high/medium linked actual losses with side_match=true suggest proxy is too aggressive"
                    ),
                    confidence="actual_backed",
                    proxy_evidence_count=len(aggressive_rows),
                    actual_backed_count=len(aggressive_rows),
                    high_link_count=sum(1 for _, link_row, _ in aggressive_rows if str(link_row.get("link_confidence", "")).strip() == "high"),
                    medium_link_count=sum(1 for _, link_row, _ in aggressive_rows if str(link_row.get("link_confidence", "")).strip() == "medium"),
                )
            )

    if coverage_complete and calibration_summary["calibration_counts"].get("proxy_too_pessimistic", 0) > 0:
        pessimistic_rows = []
        link_map = {str(row.get("actual_trade_id", "")).strip(): row for row in link_rows if str(row.get("actual_trade_id", "")).strip()}
        signal_map = {str(row.get("signal_id", "")).strip(): row for row in signal_rows if str(row.get("signal_id", "")).strip()}
        for trade_row in manual_trade_rows:
            actual_trade_id = str(trade_row.get("actual_trade_id", "")).strip()
            pnl = _mexc_parse_decimal(trade_row.get("realized_pnl", ""))
            if pnl is None or pnl <= 0:
                continue
            link_row = link_map.get(actual_trade_id, {})
            if str(link_row.get("link_confidence", "")).strip() not in {"high", "medium"}:
                continue
            signal_row = signal_map.get(str(link_row.get("signal_id", "")).strip(), {})
            if not _post_eval_watch_like(signal_row.get("prelabel", "")):
                continue
            pessimistic_rows.append((trade_row, link_row, signal_row))
        if pessimistic_rows:
            candidates.append(
                _post_eval_candidate_row(
                    report_date=inferred_report_date,
                    code="PROXY_TOO_PESSIMISTIC_REVIEW",
                    evidence_score=len(pessimistic_rows),
                    affected_area="proxy label pessimism",
                    proposed_action="review proxy pessimism candidate",
                    evidence_summary=(
                        f"{len(pessimistic_rows)} high/medium linked actual wins followed NO_TRADE/WATCH/SKIP-like proxy labels"
                    ),
                    confidence="actual_backed",
                    proxy_evidence_count=len(pessimistic_rows),
                    actual_backed_count=len(pessimistic_rows),
                    high_link_count=sum(1 for _, link_row, _ in pessimistic_rows if str(link_row.get("link_confidence", "")).strip() == "high"),
                    medium_link_count=sum(1 for _, link_row, _ in pessimistic_rows if str(link_row.get("link_confidence", "")).strip() == "medium"),
                )
            )

    if coverage_complete and (
        link_summary["high_or_medium_link_rate"] < 0.8
        or link_summary["no_candidate_count"] > 0
        or link_summary["competing_candidate_tie_count"] > 0
        or link_summary["ambiguous_count"] > 0
    ):
        candidates.append(
            _post_eval_candidate_row(
                report_date=inferred_report_date,
                code="LINKAGE_COVERAGE_REVIEW",
                evidence_score=(
                    int(round((1.0 - link_summary["high_or_medium_link_rate"]) * 10))
                    + link_summary["no_candidate_count"]
                    + link_summary["competing_candidate_tie_count"]
                    + link_summary["ambiguous_count"]
                ),
                affected_area="manual trade to signal linkage",
                proposed_action="review ambiguous links manually",
                evidence_summary=(
                    f"high_or_medium_link_rate={link_summary['high_or_medium_link_rate']:.2f}, "
                    f"no_candidate={link_summary['no_candidate_count']}, tie={link_summary['competing_candidate_tie_count']}, ambiguous={link_summary['ambiguous_count']}"
                ),
                confidence="actual_backed" if manual_trade_rows and link_rows else "proxy_backed",
                proxy_evidence_count=(
                    int(round((1.0 - link_summary["high_or_medium_link_rate"]) * 10))
                    + link_summary["no_candidate_count"]
                    + link_summary["competing_candidate_tie_count"]
                    + link_summary["ambiguous_count"]
                ),
                actual_backed_count=1 if manual_trade_rows and link_rows else 0,
            )
        )

    if coverage_complete and trade_summary["fee_missing_count"] > 0:
        candidates.append(
            _post_eval_candidate_row(
                report_date=inferred_report_date,
                code="FEE_COVERAGE_REVIEW",
                evidence_score=trade_summary["fee_missing_count"],
                affected_area="fee coverage and net PnL calibration",
                proposed_action="review fee coverage candidate",
                evidence_summary=f"{trade_summary['fee_missing_count']} manual_actual_trades rows had missing or invalid fee values",
                confidence="actual_backed",
                proxy_evidence_count=trade_summary["fee_missing_count"],
                actual_backed_count=1 if trade_summary["fee_missing_count"] else 0,
            )
        )

    if coverage_complete and (
        link_summary["ambiguous_count"] > 0
        or link_summary["no_candidate_count"] > 0
        or link_summary["competing_candidate_tie_count"] > 0
        or not actual_backed_trade_ids
    ):
        candidates.append(
            _post_eval_candidate_row(
                report_date=inferred_report_date,
                code="AMBIGUOUS_LINK_MANUAL_REVIEW",
                evidence_score=(
                    link_summary["ambiguous_count"]
                    + link_summary["no_candidate_count"]
                    + link_summary["competing_candidate_tie_count"]
                ),
                affected_area="manual trade linking ambiguity",
                proposed_action="review ambiguous links manually",
                evidence_summary=(
                    f"ambiguous={link_summary['ambiguous_count']}, no_candidate={link_summary['no_candidate_count']}, "
                    f"tie={link_summary['competing_candidate_tie_count']}"
                ),
                confidence="actual_backed" if manual_trade_rows and link_rows else "proxy_backed",
                proxy_evidence_count=(
                    link_summary["ambiguous_count"]
                    + link_summary["no_candidate_count"]
                    + link_summary["competing_candidate_tie_count"]
                ),
                actual_backed_count=1 if manual_trade_rows and link_rows else 0,
            )
        )

    input_statuses = [item["status"] for item in coverage.values()]
    if any(status != "ok" for status in input_statuses) or not candidates:
        candidates.append(
            _post_eval_candidate_row(
                report_date=inferred_report_date,
                code="INSUFFICIENT_EVIDENCE",
                evidence_score=0,
                affected_area="evidence coverage",
                proposed_action="collect more evidence before revisiting",
                evidence_summary=(
                    "some inputs are missing or header-only, or the available evidence is not yet strong enough for a ranked recommendation"
                ),
                confidence="insufficient",
            )
        )

    summary = {
        "report_date": inferred_report_date,
        "input_counts": {
            name: {"status": item["status"], "rows": item["row_count"], "fields": item["field_count"]}
            for name, item in coverage.items()
        },
        "coverage": coverage,
        "trade_summary": trade_summary,
        "link_summary": link_summary,
        "calibration_counts": calibration_summary["calibration_counts"],
        "signal_watch_positive_count": len(signal_watch_positive_rows),
        "defensive_review_count": len(defensive_review_rows),
        "balance_long_count": balance_long_count,
        "balance_short_count": balance_short_count,
        "balance_total": balance_total,
        "balance_imbalance_rate": balance_imbalance_rate,
        "turning_review_count": len(turning_rows),
        "actual_backed_trade_count": len(actual_backed_trade_ids),
        "actual_backed_link_count": actual_backed_link_count,
        "positive_actual_trade_count": positive_actual_link_count,
        "recommendation_codes": [row["recommendation_code"] for row in candidates],
        "safety_boundary": _POST_EVAL_RECOMMENDATION_SAFETY_BOUNDARY,
    }
    return candidates, summary


def rank_post_eval_recommendation_candidates(
    candidates: list[dict[str, Any]],
    *,
    report_date: str,
    coverage_complete: bool,
) -> list[dict[str, Any]]:
    ranked_candidates: list[dict[str, Any]] = []
    for candidate in candidates:
        row = dict(candidate)
        code = str(row.get("recommendation_code", "")).strip()
        proxy_evidence_count = int(row.get("proxy_evidence_count", row.get("evidence_score", 0)))
        actual_backed_count = int(row.get("actual_backed_count", 0))
        high_link_count = int(row.get("high_link_count", 0))
        medium_link_count = int(row.get("medium_link_count", 0))
        actual_backed = actual_backed_count > 0 or str(row.get("confidence", "")).strip() == "actual_backed"
        if code == "INSUFFICIENT_EVIDENCE":
            evidence_score = 0
            confidence = "insufficient"
        else:
            evidence_score = min(proxy_evidence_count, 5)
            evidence_score += min(actual_backed_count * 4, 20)
            evidence_score += min(high_link_count * 2, 10)
            evidence_score += min(medium_link_count, 5)
            confidence = "actual_backed" if actual_backed else "proxy_backed"
            if not coverage_complete and confidence != "actual_backed":
                confidence = "proxy_backed"
        row["evidence_score"] = int(evidence_score)
        row["priority"] = _post_eval_priority_from_score(int(evidence_score))
        row["confidence"] = confidence
        row["required_human_approval"] = "true"
        row["safety_note"] = _POST_EVAL_RECOMMENDATION_SAFETY_BOUNDARY
        ranked_candidates.append(row)

    ranked_candidates.sort(key=_post_eval_candidate_sort_key)
    for index, row in enumerate(ranked_candidates, start=1):
        row["rank"] = index
        row["recommendation_id"] = _post_eval_candidate_id(
            report_date=report_date,
            code=str(row.get("recommendation_code", "")).strip(),
            evidence_summary=str(row.get("evidence_summary", "")).strip(),
            evidence_score=int(row.get("evidence_score", 0)),
            rank=index,
        )
    return ranked_candidates


def build_post_eval_recommendation_report(
    *,
    base_dir: Path = BASE_DIR,
    signal_outcomes: Path | None = None,
    active_plan_candidate_outcomes: Path | None = None,
    active_plan_candidate_intraperiod_outcomes: Path | None = None,
    user_reviews: Path | None = None,
    manual_trades: Path | None = None,
    links: Path | None = None,
    output_md: Path | None = None,
    output_csv: Path | None = None,
    report_date: str | None = None,
    dry_run: bool = False,
) -> tuple[str, dict[str, Any]]:
    candidates, summary = build_post_eval_recommendation_candidates(
        base_dir=base_dir,
        signal_outcomes=signal_outcomes,
        active_plan_candidate_outcomes=active_plan_candidate_outcomes,
        active_plan_candidate_intraperiod_outcomes=active_plan_candidate_intraperiod_outcomes,
        user_reviews=user_reviews,
        manual_trades=manual_trades,
        links=links,
        report_date=report_date,
    )
    coverage_complete = all(item["status"] == "ok" for item in summary["coverage"].values())
    ranked_candidates = rank_post_eval_recommendation_candidates(
        candidates,
        report_date=summary["report_date"],
        coverage_complete=coverage_complete,
    )

    report_path = output_md or (
        base_dir / _POST_EVAL_RECOMMENDATION_OUTPUT_DIR / f"post_eval_recommendations_{summary['report_date']}.md"
    )
    output_csv_path = output_csv or base_dir / "logs" / "csv" / "post_eval_recommendation_candidates.csv"

    lines = [
        _POST_EVAL_RECOMMENDATION_HEADER,
        "",
        "## 1. Purpose Fit Summary",
        "- report-only",
        "- not FORMAL_GO",
        "- no automatic order",
        "- no private/account/order endpoints",
        "- human decides manually",
        "- ranked candidates are review-only and do not mutate thresholds, gates, labels, config, schedule, or notification text",
        "- no profitability claim is made from this report",
        "",
        "## 2. Input Coverage",
    ]
    for name, item in summary["coverage"].items():
        line = (
            f"- {name}: status={item['status']} / rows={item['row_count']} / fields={item['field_count']}"
            + (f" / latest_timestamp_jst={item['latest_timestamp_jst']}" if item["latest_timestamp_jst"] else "")
        )
        lines.append(line)

    lines.extend(
        [
            "",
            "## 3. Ranked Recommendation Candidates",
        ]
    )
    if ranked_candidates:
        for candidate in ranked_candidates:
            lines.append(
                f"- rank {candidate['rank']}: {candidate['recommendation_code']} / "
                f"priority={candidate['priority']} / confidence={candidate['confidence']} / "
                f"score={candidate['evidence_score']} / {candidate['proposed_action']}"
            )
            lines.append(f"  - evidence: {candidate['evidence_summary']}")
    else:
        lines.append("- INSUFFICIENT_EVIDENCE: evidence is not yet enough for a ranked recommendation")

    lines.extend(
        [
            "",
            "## 4. Evidence Summary",
            f"- signal_outcomes rows: {summary['input_counts']['signal_outcomes']['rows']}",
            f"- user_reviews rows: {summary['input_counts']['user_reviews']['rows']}",
            f"- manual_actual_trades rows: {summary['input_counts']['manual_trades']['rows']}",
            f"- manual_trade_signal_links rows: {summary['input_counts']['links']['rows']}",
            f"- actual_backed_trade_count: {summary['actual_backed_trade_count']}",
            f"- actual_backed_link_count: {summary['actual_backed_link_count']}",
            f"- calibration proxy_too_aggressive: {summary['calibration_counts'].get('proxy_too_aggressive', 0)}",
            f"- calibration proxy_too_pessimistic: {summary['calibration_counts'].get('proxy_too_pessimistic', 0)}",
            f"- calibration ambiguous_needs_review: {summary['calibration_counts'].get('ambiguous_needs_review', 0)}",
            "",
            "## 5. Long/Short Balance Review",
            f"- long_count: {summary['balance_long_count']}",
            f"- short_count: {summary['balance_short_count']}",
            f"- total_balance_rows: {summary['balance_total']}",
            f"- imbalance_rate: {summary['balance_imbalance_rate']:.4f}",
            "",
            "## 6. Over-Suppression Review",
            f"- NO_TRADE/watch positive proxy rows: {summary['signal_watch_positive_count']}",
            f"- defensive subject rows: {summary['defensive_review_count']}",
            "",
            "## 7. Turning Brake Review",
            f"- turning/counter rows with brake evidence: {summary['turning_review_count']}",
            "",
            "## 8. Linkage and Ground Truth Coverage",
            f"- total_link_rows: {summary['link_summary']['total_link_rows']}",
            f"- linked_rows: {summary['link_summary']['linked_rows']}",
            f"- high_or_medium_link_rate: {summary['link_summary']['high_or_medium_link_rate']:.4f}",
            f"- no_candidate_count: {summary['link_summary']['no_candidate_count']}",
            f"- competing_candidate_tie_count: {summary['link_summary']['competing_candidate_tie_count']}",
            f"- ambiguous_count: {summary['link_summary']['ambiguous_count']}",
            f"- fee_missing_count: {summary['trade_summary']['fee_missing_count']}",
            "",
            "## 9. Human Approval Required",
            "- Human approval is required before any production wording/config/threshold/gate/runtime changes.",
            "- This report only proposes review candidates; it does not change behavior.",
            "",
            "## 10. Safety Boundary",
            f"- {_POST_EVAL_RECOMMENDATION_SAFETY_BOUNDARY}",
            "",
            "## 11. Limitations",
        ]
    )
    limitations: list[str] = []
    if any(item["status"] != "ok" for item in summary["coverage"].values()):
        limitations.append("some inputs are missing or header-only")
    if not ranked_candidates or any(candidate["recommendation_code"] == "INSUFFICIENT_EVIDENCE" for candidate in ranked_candidates):
        limitations.append("evidence is still insufficient for a strong recommendation")
    if summary["trade_summary"]["fee_missing_count"]:
        limitations.append("fee coverage is incomplete")
    if summary["link_summary"]["ambiguous_count"] or summary["link_summary"]["no_candidate_count"] or summary["link_summary"]["competing_candidate_tie_count"]:
        limitations.append("link ambiguity remains and requires manual review")
    if not limitations:
        limitations.append("no major structural limitation was detected, but this remains report-only evidence for human review")
    for item in limitations:
        lines.append(f"- {item}")

    report = "\n".join(lines) + "\n"
    if not dry_run:
        _ensure_parent(report_path)
        report_path.write_text(report, encoding="utf-8")
        _write_csv_rows(output_csv_path, _POST_EVAL_RECOMMENDATION_CSV_HEADER, ranked_candidates)

    payload = {
        "schema_version": "post_eval_recommendations.v1",
        "report_date": summary["report_date"],
        "report_path": str(report_path),
        "output_csv_path": str(output_csv_path),
        "input_counts": summary["input_counts"],
        "candidate_count": len(ranked_candidates),
        "top_recommendation_codes": [row["recommendation_code"] for row in ranked_candidates[:3]],
        "priority_counts": dict(Counter(str(row.get("priority", "low")).strip() for row in ranked_candidates)),
        "confidence_counts": dict(Counter(str(row.get("confidence", "proxy_backed")).strip() for row in ranked_candidates)),
        "safety_boundary": _POST_EVAL_RECOMMENDATION_SAFETY_BOUNDARY,
    }
    return report, payload


def _user_reviews_archive_path(base_dir: Path) -> Path:
    return base_dir / "logs" / "csv" / "user_reviews_human_archive.csv"


def _ai_post_review_dir(base_dir: Path) -> Path:
    return base_dir / "logs" / "review" / "ai_post_reviews"


def _ai_post_review_chart_dir(base_dir: Path) -> Path:
    return base_dir / "logs" / "review" / "chart_snapshots"


def _archive_existing_reviews(base_dir: Path, reviews_path: Path) -> Path | None:
    rows = _load_csv_rows(reviews_path)
    if not rows:
        return None
    archive_path = _user_reviews_archive_path(base_dir)
    if archive_path.exists():
        return archive_path
    fieldnames = list(rows[0].keys())
    _write_csv_rows(archive_path, fieldnames, rows)
    return archive_path


def _utc_now_iso() -> str:
    return datetime.now(tz=timezone.utc).isoformat().replace("+00:00", "Z")


def _review_source_value(row: dict[str, Any]) -> str:
    source = str(row.get("review_source", "")).strip()
    if source in VALID_REVIEW_SOURCE:
        return source
    if str(row.get("review_status", "")).strip() == "done":
        return "human_override"
    return ""


def _review_source_badge(row: dict[str, Any]) -> tuple[str, str]:
    source = _review_source_value(row)
    if source == "ai":
        model = str(row.get("review_model", "")).strip()
        image_mode = str(row.get("review_image_mode", "")).strip()
        detail_parts: list[str] = []
        if model:
            detail_parts.append(model)
        if image_mode == "price_map_svg":
            detail_parts.append("画像あり")
        elif image_mode == "numeric_only_fallback":
            detail_parts.append("数値のみ")
        detail = " / ".join(detail_parts)
        label = "AI評価済み"
        return label, detail
    if source == "human_override":
        return "人が確認・修正済み", ""
    if str(row.get("evaluation_status", "")).strip() == "complete":
        return "AIレビュー待ち", ""
    return "24時間後評価待ち", ""


def _review_source_badge_class(row: dict[str, Any]) -> str:
    source = _review_source_value(row)
    if source == "ai":
        return "ai"
    if source == "human_override":
        return "human_override"
    if str(row.get("evaluation_status", "")).strip() == "complete":
        return "awaiting_ai"
    return "awaiting_outcome"


def _review_workflow_steps(row: dict[str, Any]) -> list[tuple[str, str, str]]:
    evaluation_complete = str(row.get("evaluation_status", "")).strip() == "complete"
    source = _review_source_value(row)

    machine_status = "完了" if evaluation_complete else "待ち"
    machine_class = "done" if evaluation_complete else "waiting"

    if source in {"ai", "human_override"}:
        ai_status = "完了"
        ai_class = "done"
    elif evaluation_complete:
        ai_status = "待ち"
        ai_class = "waiting"
    else:
        ai_status = "未着手"
        ai_class = "idle"

    human_status = "済" if source == "human_override" else "未"
    human_class = "done" if source == "human_override" else "idle"

    return [
        ("24時間後機械評価", machine_status, machine_class),
        ("AIレビュー", ai_status, ai_class),
        ("人が確認", human_status, human_class),
    ]


def _extract_price_map_svg(html_text: str) -> str:
    match = re.search(r'(<svg[^>]*class="price-map"[\s\S]*?</svg>)', html_text)
    return match.group(1) if match else ""


def _signal_snapshot_path(base_dir: Path, signal_id: str) -> Path:
    return base_dir / "logs" / "signals" / f"{signal_id}.json"


def _recompute_current_setup_details(base_dir: Path, signal_id: str) -> dict[str, Any]:
    payload = load_json(_signal_snapshot_path(base_dir, signal_id))
    if not isinstance(payload, dict):
        return {}
    side = str(payload.get("primary_setup_side") or payload.get("bias") or "").strip().lower()
    if side not in {"long", "short"}:
        return {}
    try:
        price = float(payload.get("current_price", 0.0))
        atr = float(payload.get("atr_15m_value", 0.0))
        confidence = int(float(payload.get("confidence", 0.0)))
        funding_rate = float(payload.get("funding_rate_pct", 0.0))
        atr_ratio = float(payload.get("atr_ratio", 0.0))
        volume_ratio = float(payload.get("volume_ratio", 0.0))
        trigger_threshold = float(payload.get("trigger_volume_ratio_threshold", 0.0))
    except (TypeError, ValueError):
        return {}
    try:
        cfg = load_config(base_dir)
    except Exception:  # noqa: BLE001
        cfg = type(
            "_RRReplayCfg",
            (),
            {
                "SL_ATR_MULTIPLIER": 1.5,
                "MIN_RR_RATIO": 1.1,
                "CONFIDENCE_LONG_MIN": 45,
                "CONFIDENCE_SHORT_MIN": 55,
                "MIN_ACCEPTABLE_ATR_RATIO": 0.25,
                "MAX_ACCEPTABLE_ATR_RATIO": 2.4,
                "FUNDING_LONG_WARNING": 0.06,
                "FUNDING_LONG_PROHIBITED": 0.10,
                "FUNDING_SHORT_WARNING": -0.04,
                "FUNDING_SHORT_PROHIBITED": -0.07,
            },
        )()
    support_zones = payload.get("support_zones_all") or []
    resistance_zones = payload.get("resistance_zones_all") or []
    if not isinstance(support_zones, list) or not isinstance(resistance_zones, list):
        return {}
    warning_flags = payload.get("warning_flags") or []
    warning_count = len(_split_values(warning_flags)) if isinstance(warning_flags, str) else len(warning_flags)
    trigger_ready = bool(payload.get("breakout_up" if side == "long" else "breakout_down")) or volume_ratio >= trigger_threshold
    setup, _ = build_setup(
        side=side,
        price=price,
        atr=atr,
        support_zones=support_zones,
        resistance_zones=resistance_zones,
        sl_atr_multiplier=float(getattr(cfg, "SL_ATR_MULTIPLIER", 1.5)),
        min_rr_ratio=float(getattr(cfg, "MIN_RR_RATIO", 1.1)),
        confidence=confidence,
        confidence_min=int(getattr(cfg, "CONFIDENCE_LONG_MIN" if side == "long" else "CONFIDENCE_SHORT_MIN", 45)),
        atr_ratio=atr_ratio,
        atr_ratio_min=float(getattr(cfg, "MIN_ACCEPTABLE_ATR_RATIO", 0.25)),
        atr_ratio_max=float(getattr(cfg, "MAX_ACCEPTABLE_ATR_RATIO", 2.4)),
        funding_rate=funding_rate,
        funding_warning=float(getattr(cfg, "FUNDING_LONG_WARNING" if side == "long" else "FUNDING_SHORT_WARNING", 0.0)),
        funding_prohibited=float(getattr(cfg, "FUNDING_LONG_PROHIBITED" if side == "long" else "FUNDING_SHORT_PROHIBITED", 0.0)),
        trigger_ready=trigger_ready,
        warning_count=warning_count,
    )
    return {
        "signal_id": signal_id,
        "status": str(setup.get("status", "")),
        "reason": str(setup.get("status_reason_code", "")),
        "rr": _parse_float(setup.get("rr_estimate", 0.0), 0.0),
    }


def _recompute_current_setup_summary(base_dir: Path, signal_id: str) -> str:
    details = _recompute_current_setup_details(base_dir, signal_id)
    if not details:
        return ""
    return (
        f"{signal_id}=>{details.get('status', '')}/{details.get('reason', '')}"
        f"/rr={_parse_float(details.get('rr', 0.0), 0.0):.2f}"
    )


def _timestamp_in_jst_date_range(timestamp_jst: str, *, date_from: str = "", date_to: str = "") -> bool:
    dt = _parse_dt(timestamp_jst)
    if dt is None:
        return False
    current_date = dt.astimezone(JST).date()
    if date_from:
        from_date = datetime.fromisoformat(date_from).date()
        if current_date < from_date:
            return False
    if date_to:
        to_date = datetime.fromisoformat(date_to).date()
        if current_date > to_date:
            return False
    return True


def build_current_setup_comparison_report(
    *,
    base_dir: Path,
    shadow_path: Path | None = None,
    output_md: Path | None = None,
    limit: int = 20,
    only_notified: bool = False,
    previous_reason: str = "",
    current_reason: str = "",
    prelabel: str = "",
    risk_flag: str = "",
    date_from: str = "",
    date_to: str = "",
    status_transition: str = "",
) -> str:
    shadow_path = shadow_path or base_dir / "logs" / "csv" / "shadow_log.csv"
    rows = _load_csv_rows(shadow_path)
    differences: list[dict[str, Any]] = []
    previous_reason_filter = previous_reason.strip()
    current_reason_filter = current_reason.strip()
    prelabel_filter = prelabel.strip().upper()
    risk_flag_filter = risk_flag.strip()
    date_from_filter = date_from.strip()
    date_to_filter = date_to.strip()
    status_transition_filter = status_transition.strip()
    for row in rows:
        signal_id = str(row.get("signal_id", "")).strip()
        if not signal_id:
            continue
        timestamp_jst = str(row.get("timestamp_jst", "")).strip()
        if (date_from_filter or date_to_filter) and not _timestamp_in_jst_date_range(
            timestamp_jst,
            date_from=date_from_filter,
            date_to=date_to_filter,
        ):
            continue
        current = _recompute_current_setup_details(base_dir, signal_id)
        if not current:
            continue
        previous_status = str(row.get("primary_setup_status", "")).strip()
        previous_reason = str(row.get("primary_setup_reason", "")).strip()
        current_status = str(current.get("status", "")).strip()
        current_reason = str(current.get("reason", "")).strip()
        if previous_status == current_status and previous_reason == current_reason:
            continue
        current_status_transition = f"{previous_status}->{current_status}"
        normalized_prelabel = str(row.get("prelabel", "")).strip().upper()
        notified = _parse_bool(row.get("was_notified"))
        row_risk_flags = _split_values(row.get("risk_flags", ""))
        if only_notified and not notified:
            continue
        if previous_reason_filter and previous_reason != previous_reason_filter:
            continue
        if current_reason_filter and current_reason != current_reason_filter:
            continue
        if prelabel_filter and normalized_prelabel != prelabel_filter:
            continue
        if risk_flag_filter and risk_flag_filter not in row_risk_flags:
            continue
        if status_transition_filter and current_status_transition != status_transition_filter:
            continue
        differences.append(
            {
                "signal_id": signal_id,
                "timestamp_jst": timestamp_jst,
                "prelabel": normalized_prelabel,
                "previous_status": previous_status,
                "previous_reason": previous_reason,
                "current_status": current_status,
                "current_reason": current_reason,
                "current_rr": _parse_float(current.get("rr", 0.0), 0.0),
                "notified": notified,
                "risk_flags": row_risk_flags,
                "notify_reasons": _parse_maybe_json_array(str(row.get("notify_reason", ""))),
                "execution_shadow": _parse_float(row.get("confidence_execution_shadow"), 0.0),
                "wait_shadow": _parse_float(row.get("confidence_wait_shadow"), 0.0),
            }
        )

    differences.sort(key=lambda item: str(item.get("timestamp_jst", "")), reverse=True)
    status_changes = Counter(f"{item['previous_status']}->{item['current_status']}" for item in differences)
    reason_changes = Counter(f"{item['previous_reason']}->{item['current_reason']}" for item in differences)
    notified_count = sum(1 for item in differences if item["notified"])
    risk_flag_counts: Counter[str] = Counter()
    notify_reason_counts: Counter[str] = Counter()
    status_group_counts: Counter[str] = Counter()
    for item in differences:
        risk_flag_counts.update(item["risk_flags"])
        notify_reason_counts.update(item["notify_reasons"])
        status_group_counts[item["previous_status"] + "->" + item["current_status"]] += 1
    avg_execution = _mean_value(differences, "execution_shadow")
    avg_wait = _mean_value(differences, "wait_shadow")

    lines = ["# 現行 Setup 比較", ""]
    lines.append(f"- 比較対象 shadow 行数: {len(rows)}")
    if only_notified:
        lines.append("- フィルタ: 通知済みのみ")
    if previous_reason_filter:
        lines.append(f"- フィルタ: 旧 reason={previous_reason_filter}")
    if current_reason_filter:
        lines.append(f"- フィルタ: 現行 reason={current_reason_filter}")
    if prelabel_filter:
        lines.append(f"- フィルタ: prelabel={prelabel_filter}")
    if risk_flag_filter:
        lines.append(f"- フィルタ: risk_flag={risk_flag_filter}")
    if date_from_filter:
        lines.append(f"- フィルタ: date_from={date_from_filter}")
    if date_to_filter:
        lines.append(f"- フィルタ: date_to={date_to_filter}")
    if status_transition_filter:
        lines.append(f"- フィルタ: status_transition={status_transition_filter}")
    lines.append(f"- 現行 setup との差分あり: {len(differences)}")
    lines.append(f"- 差分ありのうち通知済み: {notified_count}")
    if differences:
        lines.append(f"- 平均 execution_shadow: {avg_execution:.1f}")
        lines.append(f"- 平均 wait_shadow: {avg_wait:.1f}")
    if status_changes:
        lines.append("- 主な status 変化: " + ", ".join(f"{label}={count}件" for label, count in status_changes.most_common(5)))
    if reason_changes:
        lines.append("- 主な reason 変化: " + ", ".join(f"{label}={count}件" for label, count in reason_changes.most_common(5)))
    if risk_flag_counts:
        lines.append("- 主な risk_flags: " + ", ".join(f"{label}={count}件" for label, count in risk_flag_counts.most_common(5)))
    if notify_reason_counts:
        lines.append("- 主な通知理由: " + ", ".join(f"{label}={count}件" for label, count in notify_reason_counts.most_common(5)))
    lines.append("")
    if status_group_counts:
        lines.append("## status別集計")
        for label, count in status_group_counts.most_common(5):
            subset = [item for item in differences if item["previous_status"] + "->" + item["current_status"] == label]
            lines.append(
                f"- {label}: {count}件 / 平均 execution={_mean_value(subset, 'execution_shadow'):.1f} / 平均 wait={_mean_value(subset, 'wait_shadow'):.1f}"
            )
        lines.append("")
    lines.append("## 代表例")
    if differences:
        for item in differences[:limit]:
            lines.append(
                f"- {item['signal_id']}: {item['previous_status']}/{item['previous_reason']} -> "
                f"{item['current_status']}/{item['current_reason']} / rr={item['current_rr']:.2f} / "
                f"prelabel={item['prelabel']} / notified={'yes' if item['notified'] else 'no'}"
            )
    else:
        lines.append("- 差分はありません")
    report = "\n".join(lines) + "\n"
    if output_md is not None:
        _ensure_parent(output_md)
        output_md.write_text(report, encoding="utf-8")
    return report


def refresh_standard_setup_comparison_reports(
    *,
    base_dir: Path,
    shadow_path: Path | None = None,
    analysis_dir: Path | None = None,
    limit: int = 20,
    date_from: str = "",
    date_to: str = "",
) -> dict[str, Path]:
    analysis_dir = analysis_dir or base_dir / "運用資料" / "reports" / "analysis"
    specs = [
        {
            "key": "notified_rr_to_entry",
            "filename": "notified_rr_to_entry.md",
            "only_notified": True,
            "previous_reason": "rr_below_min",
            "current_reason": "entry_zone_not_reached",
        },
        {
            "key": "notified_rr_to_entry_orderbook_ask_heavy",
            "filename": "notified_rr_to_entry_orderbook_ask_heavy.md",
            "only_notified": True,
            "previous_reason": "rr_below_min",
            "current_reason": "entry_zone_not_reached",
            "risk_flag": "orderbook_ask_heavy",
        },
        {
            "key": "rr_to_confidence",
            "filename": "rr_to_confidence.md",
            "previous_reason": "rr_below_min",
            "current_reason": "confidence_below_min",
        },
    ]
    generated: dict[str, Path] = {}
    for spec in specs:
        output_md = analysis_dir / str(spec["filename"])
        build_current_setup_comparison_report(
            base_dir=base_dir,
            shadow_path=shadow_path,
            output_md=output_md,
            limit=limit,
            only_notified=bool(spec.get("only_notified", False)),
            previous_reason=str(spec.get("previous_reason", "")),
            current_reason=str(spec.get("current_reason", "")),
            risk_flag=str(spec.get("risk_flag", "")),
            date_from=date_from,
            date_to=date_to,
        )
        generated[str(spec["key"])] = output_md
    return generated


def _age_bucket_label(timestamp_jst: str, *, now: datetime | None = None) -> str:
    dt = _parse_dt(timestamp_jst)
    if dt is None:
        return "不明"
    current = (now or datetime.now(tz=JST)).astimezone(JST)
    age_days = max(0, (current.date() - dt.astimezone(JST).date()).days)
    if age_days <= 1:
        return "0-1日"
    if age_days <= 3:
        return "2-3日"
    if age_days <= 7:
        return "4-7日"
    return "8日以上"


def _filtered_shadow_rows(
    *,
    shadow_path: Path,
    date_from: str = "",
    date_to: str = "",
) -> tuple[list[dict[str, str]], list[dict[str, str]]]:
    rows = _load_csv_rows(shadow_path)
    date_from_filter = date_from.strip()
    date_to_filter = date_to.strip()
    filtered_rows = [
        row
        for row in rows
        if not (date_from_filter or date_to_filter)
        or _timestamp_in_jst_date_range(str(row.get("timestamp_jst", "")).strip(), date_from=date_from_filter, date_to=date_to_filter)
    ]
    return rows, filtered_rows


def _collect_relax_candidates(rows: list[dict[str, str]]) -> list[dict[str, Any]]:
    blocked_rows = [row for row in rows if str(row.get("phase1_observation_gate", "")).strip() == "blocked"]
    combo_flags = {"orderbook_ask_heavy", "ask_wall_close", "long_flush_exhaustion"}
    candidates: list[dict[str, Any]] = []
    for row in blocked_rows:
        reasons = _split_values(str(row.get("phase1_observation_reasons", "")))
        if "confidence_below_min" not in reasons:
            continue
        risk_flags = _split_values(str(row.get("risk_flags", "")))
        if "sweep_incomplete" not in risk_flags or "lower_liquidity_close" not in risk_flags:
            continue
        if any(flag in combo_flags for flag in risk_flags):
            continue
        candidates.append(
            {
                "signal_id": str(row.get("signal_id", "")).strip(),
                "timestamp_jst": str(row.get("timestamp_jst", "")).strip(),
                "prelabel": str(row.get("prelabel", "")).strip(),
                "setup_reason": str(row.get("primary_setup_reason", "")).strip(),
                "execution": _parse_float(row.get("confidence_execution_shadow"), 0.0),
                "wait": _parse_float(row.get("confidence_wait_shadow"), 0.0),
                "phase1_reasons": _split_values(str(row.get("phase1_observation_reasons", ""))),
                "risk_flags": risk_flags,
            }
        )
    candidates.sort(key=lambda row: row["timestamp_jst"], reverse=True)
    return candidates


