def _normalize_actionability_shadow_summary_value(value: Any) -> str:
    normalized = str(value).strip() if value is not None else ""
    return normalized if normalized else "UNKNOWN"


def _load_actionability_shadow_summary_rows(
    *,
    input_csv: Path,
    parser: argparse.ArgumentParser | None = None,
) -> list[dict[str, str]]:
    if input_csv.name == "paper_positions.csv":
        message = "input_csv must not be paper_positions.csv"
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    if not input_csv.exists():
        message = f"input_csv does not exist: {input_csv}"
        if parser is None:
            raise FileNotFoundError(message)
        parser.error(message)
    rows, fieldnames = _load_csv_rows_with_fieldnames(input_csv)
    missing_columns = [column for column in ACTIONABILITY_SHADOW_DECISION_HEADER if column not in fieldnames]
    if missing_columns:
        message = "input_csv missing required columns: " + ", ".join(missing_columns)
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    normalized_rows: list[dict[str, str]] = []
    for row in rows:
        normalized_rows.append(
            {column: str(row.get(column, "")).strip() if row.get(column) is not None else "" for column in ACTIONABILITY_SHADOW_DECISION_HEADER}
        )
    return normalized_rows


def _actionability_shadow_summary_section_lines(
    *,
    section_title: str,
    rows: list[dict[str, str]],
    field_name: str,
) -> list[str]:
    counts = Counter(_normalize_actionability_shadow_summary_value(row.get(field_name, "")) for row in rows)
    lines = [f"## {section_title}", ""]
    if counts:
        for label in sorted(counts):
            lines.append(f"- {label}: {counts[label]}件")
    else:
        lines.append("- none")
    lines.append("")
    return lines


def build_actionability_shadow_decision_summary(
    *,
    input_csv: Path,
    output_md: Path | None = None,
    parser: argparse.ArgumentParser | None = None,
) -> str:
    rows = _load_actionability_shadow_summary_rows(input_csv=input_csv, parser=parser)
    lines = [
        "# Actionability Shadow Decision Summary",
        "",
        "- safety boundary: report-only, not FORMAL_GO, no automatic order, human decides manually",
        f"- total row count: {len(rows)}",
        "",
    ]
    lines.extend(
        _actionability_shadow_summary_section_lines(
            section_title="Counts by actionability_label",
            rows=rows,
            field_name="actionability_label",
        )
    )
    lines.extend(
        _actionability_shadow_summary_section_lines(
            section_title="Counts by human_action",
            rows=rows,
            field_name="human_action",
        )
    )
    lines.extend(
        _actionability_shadow_summary_section_lines(
            section_title="Counts by active_plan_label",
            rows=rows,
            field_name="active_plan_label",
        )
    )
    lines.extend(
        _actionability_shadow_summary_section_lines(
            section_title="Counts by final_outcome",
            rows=rows,
            field_name="final_outcome",
        )
    )
    lines.extend(
        _actionability_shadow_summary_section_lines(
            section_title="Counts by source_readiness",
            rows=rows,
            field_name="source_readiness",
        )
    )
    report = "\n".join(lines) + "\n"
    if output_md is not None:
        _ensure_parent(output_md)
        output_md.write_text(report, encoding="utf-8")
    return report


def _load_daily_proxy_input_rows(path: Path) -> tuple[list[dict[str, str]], list[str], str, int]:
    if not path.exists():
        return [], [], "missing", 0
    try:
        with path.open("r", newline="", encoding="utf-8") as fp:
            reader = csv.DictReader(fp)
            fieldnames = list(reader.fieldnames or [])
            if not fieldnames:
                return [], [], "header_only", 0
            rows: list[dict[str, str]] = []
            parse_warning_rows = 0
            for raw_row in reader:
                if None in raw_row:
                    parse_warning_rows += 1
                row = {key: ("" if value is None else str(value)) for key, value in raw_row.items() if key is not None}
                rows.append(row)
            if not rows:
                return [], fieldnames, "header_only", 0
            status = "parse_warning" if parse_warning_rows else "read_ok"
            return rows, fieldnames, status, parse_warning_rows
    except csv.Error:
        return [], [], "parse_warning", 0


def _count_selected_proxy_rows(
    rows: list[dict[str, str]],
    *,
    window_start: datetime,
    window_end: datetime,
) -> tuple[list[dict[str, str]], int]:
    selected_rows: list[dict[str, str]] = []
    parse_warning_rows = 0
    for row in rows:
        raw_timestamp = str(row.get("timestamp_jst", "")).strip()
        dt = _parse_dt(raw_timestamp)
        if dt is None:
            if raw_timestamp:
                parse_warning_rows += 1
            continue
        row_date = dt.astimezone(JST).date()
        if window_start.date() <= row_date <= window_end.date():
            selected_rows.append(row)
    return selected_rows, parse_warning_rows


def _counter_from_rows(rows: list[dict[str, Any]], field: str) -> Counter[str]:
    counter: Counter[str] = Counter()
    for row in rows:
        value = str(row.get(field, "")).strip() or "blank"
        counter[value] += 1
    return counter


def _counter_from_bool_rows(rows: list[dict[str, Any]], field: str) -> int:
    return sum(1 for row in rows if _parse_bool(row.get(field, "")))


def _mean_numeric_rows(rows: list[dict[str, Any]], field: str) -> float:
    values = []
    for row in rows:
        raw_value = str(row.get(field, "")).strip()
        if not raw_value:
            continue
        value = _parse_float(raw_value, default=float("nan"))
        if value == value:
            values.append(value)
    return mean(values) if values else 0.0


def _proxy_counter_line(counter: Counter[str], *, limit: int = 8) -> str:
    return _format_counter(counter, limit=limit)


def _daily_proxy_recommendations(
    *,
    signal_rows: list[dict[str, str]],
    candidate_rows: list[dict[str, str]],
    intraperiod_rows: list[dict[str, str]],
    user_review_rows: list[dict[str, str]],
    required_input_statuses: dict[str, str],
) -> list[tuple[str, str]]:
    recommendations: list[tuple[str, str]] = []
    if any(status in {"missing", "header_only"} for status in required_input_statuses.values()):
        recommendations.append(("INPUT_COVERAGE_REVIEW", "one or more required inputs are missing or header-only"))

    signal_skip_too_strict = sum(1 for row in signal_rows if str(row.get("skip_outcome", "")).strip() == "skip_too_strict")
    no_action_tp1_first = sum(
        1
        for row in intraperiod_rows
        if str(row.get("active_primary_action", "")).strip() == "NO_ACTION"
        and str(row.get("outcome", "")).strip() == "tp1_first"
    )
    if signal_skip_too_strict > 0 or no_action_tp1_first > 0:
        reason_bits = []
        if signal_skip_too_strict > 0:
            reason_bits.append(f"skip_too_strict={signal_skip_too_strict}")
        if no_action_tp1_first > 0:
            reason_bits.append(f"NO_ACTION+tp1_first={no_action_tp1_first}")
        recommendations.append(("NO_TRADE_SPLIT_CANDIDATE", ", ".join(reason_bits) or "proxy suppression candidates present"))

    tp1_first_count = sum(1 for row in intraperiod_rows if str(row.get("outcome", "")).strip() == "tp1_first")
    sl_first_count = sum(1 for row in intraperiod_rows if str(row.get("outcome", "")).strip() == "sl_first")
    if sl_first_count > max(0, tp1_first_count):
        recommendations.append(
            (
                "AGGRESSION_RISK_REVIEW",
                f"sl_first={sl_first_count} exceeds tp1_first={tp1_first_count}",
            )
        )

    side_counts = _counter_from_rows(candidate_rows, "side")
    if candidate_rows:
        dominant_side, dominant_count = side_counts.most_common(1)[0]
        if dominant_count / len(candidate_rows) >= 0.65:
            recommendations.append(
                (
                    "LONG_SHORT_BALANCE_REVIEW",
                    f"{dominant_side} dominates {dominant_count}/{len(candidate_rows)} candidate rows",
                )
            )

    defensive_terms = ("売買非推奨", "実行不可", "実弾不可", "注意報")
    defensive_wording_count = sum(
        1
        for row in user_review_rows
        if any(term in str(row.get("subject", "")) for term in defensive_terms)
    )
    if defensive_wording_count > 0:
        recommendations.append(
            (
                "SUBJECT_TOO_DEFENSIVE_REVIEW",
                f"defensive subject wording count={defensive_wording_count}",
            )
        )

    if not recommendations:
        recommendations.append(("KEEP_MONITORING", "no proxy warning threshold crossed"))
    return recommendations


def _build_daily_proxy_evaluator_report_data(
    *,
    base_dir: Path = BASE_DIR,
    output_md: Path | None = None,
    report_date: str | None = None,
    lookback_days: int = 7,
) -> tuple[str, dict[str, Any]]:
    input_specs = [
        ("signal_outcomes", base_dir / "logs" / "csv" / "signal_outcomes.csv"),
        ("active_plan_candidate_outcomes", base_dir / "logs" / "csv" / "active_plan_candidate_outcomes.csv"),
        ("active_plan_candidate_intraperiod_outcomes", base_dir / "logs" / "csv" / "active_plan_candidate_intraperiod_outcomes.csv"),
        ("user_reviews", base_dir / "logs" / "csv" / "user_reviews.csv"),
    ]
    loaded_inputs: dict[str, dict[str, Any]] = {}
    all_timestamps: list[datetime] = []
    parse_warning_count = 0
    for key, path in input_specs:
        rows, fieldnames, status, malformed_rows = _load_daily_proxy_input_rows(path)
        timestamp_parse_warnings = 0
        for row in rows:
            raw_timestamp = str(row.get("timestamp_jst", "")).strip()
            if not raw_timestamp:
                continue
            dt = _parse_dt(raw_timestamp)
            if dt is None:
                timestamp_parse_warnings += 1
            else:
                all_timestamps.append(dt.astimezone(JST))
        if status == "read_ok" and timestamp_parse_warnings > 0:
            status = "parse_warning"
        if timestamp_parse_warnings > 0:
            parse_warning_count += timestamp_parse_warnings
        if malformed_rows > 0:
            parse_warning_count += malformed_rows
            if status == "read_ok":
                status = "parse_warning"
        loaded_inputs[key] = {
            "path": path,
            "rows": rows,
            "fieldnames": fieldnames,
            "status": status,
            "parse_warning_rows": malformed_rows + timestamp_parse_warnings,
            "total_rows": len(rows),
        }

    resolved_report_date = (str(report_date or "").strip() if report_date else "")
    if resolved_report_date:
        report_dt = datetime.strptime(resolved_report_date, "%Y%m%d").replace(tzinfo=JST)
    elif all_timestamps:
        latest_dt = max(all_timestamps).astimezone(JST)
        resolved_report_date = latest_dt.strftime("%Y%m%d")
        report_dt = latest_dt
    else:
        report_dt = datetime.now(tz=JST)
        resolved_report_date = report_dt.strftime("%Y%m%d")

    window_days = max(1, int(lookback_days))
    window_end = report_dt.astimezone(JST).date()
    window_start = window_end - timedelta(days=window_days - 1)
    window_start_dt = datetime.combine(window_start, datetime.min.time(), tzinfo=JST)
    window_end_dt = datetime.combine(window_end, datetime.max.time(), tzinfo=JST)

    for bundle in loaded_inputs.values():
        selected_rows, extra_parse_warnings = _count_selected_proxy_rows(
            bundle["rows"],
            window_start=window_start_dt,
            window_end=window_end_dt,
        )
        bundle["selected_rows"] = selected_rows
        bundle["selected_row_count"] = len(selected_rows)
        bundle["parse_warning_rows"] += extra_parse_warnings
        if extra_parse_warnings > 0 and bundle["status"] == "read_ok":
            bundle["status"] = "parse_warning"

    signal_rows = loaded_inputs["signal_outcomes"]["selected_rows"]
    candidate_rows = loaded_inputs["active_plan_candidate_outcomes"]["selected_rows"]
    intraperiod_rows = loaded_inputs["active_plan_candidate_intraperiod_outcomes"]["selected_rows"]
    user_review_rows = loaded_inputs["user_reviews"]["selected_rows"]

    report_path = output_md or (
        base_dir
        / DAILY_PROXY_EVALUATOR_OUTPUT_DIR
        / f"daily_proxy_evaluator_{resolved_report_date}.md"
    )

    signal_bias_counts = _counter_from_rows(signal_rows, "bias")
    signal_prelabel_counts = _counter_from_rows(signal_rows, "prelabel")
    signal_direction_counts = _counter_from_rows(signal_rows, "direction_outcome")
    signal_entry_counts = _counter_from_rows(signal_rows, "entry_outcome")
    signal_wait_counts = _counter_from_rows(signal_rows, "wait_outcome")
    signal_skip_counts = _counter_from_rows(signal_rows, "skip_outcome")
    signal_outcome_counts = _counter_from_rows(signal_rows, "outcome")
    signal_skip_too_strict_count = signal_skip_counts.get("skip_too_strict", 0)
    signal_good_entry_count = signal_entry_counts.get("good_entry", 0)

    candidate_side_counts = _counter_from_rows(candidate_rows, "side")
    candidate_type_counts = _counter_from_rows(candidate_rows, "candidate_type")
    candidate_action_counts = _counter_from_rows(candidate_rows, "active_primary_action")
    candidate_status_counts = _counter_from_rows(candidate_rows, "candidate_status")
    candidate_direction_counts = _counter_from_rows(candidate_rows, "outcome_direction_outcome")
    candidate_tp1_close_count = _counter_from_bool_rows(candidate_rows, "tp1_close_reached_24h")
    candidate_sl_close_count = _counter_from_bool_rows(candidate_rows, "sl_close_reached_24h")

    intraperiod_side_counts = _counter_from_rows(intraperiod_rows, "side")
    intraperiod_type_counts = _counter_from_rows(intraperiod_rows, "candidate_type")
    intraperiod_action_counts = _counter_from_rows(intraperiod_rows, "active_primary_action")
    intraperiod_outcome_counts = _counter_from_rows(intraperiod_rows, "outcome")
    intraperiod_exit_reason_counts = _counter_from_rows(intraperiod_rows, "first_exit_reason")
    intraperiod_tp1_count = intraperiod_outcome_counts.get("tp1_first", 0)
    intraperiod_sl_count = intraperiod_outcome_counts.get("sl_first", 0)
    intraperiod_timeout_count = intraperiod_outcome_counts.get("timeout", 0)
    intraperiod_no_ohlcv_count = intraperiod_outcome_counts.get("no_ohlcv", 0)
    intraperiod_mfe_r_avg = _mean_numeric_rows(intraperiod_rows, "mfe_r")
    intraperiod_mae_r_avg = _mean_numeric_rows(intraperiod_rows, "mae_r")

    review_status_counts = _counter_from_rows(user_review_rows, "review_status")
    review_verdict_counts = _counter_from_rows(user_review_rows, "user_verdict")
    review_would_trade_counts = _counter_from_rows(user_review_rows, "would_trade")
    review_source_counts = _counter_from_rows(user_review_rows, "review_source")
    review_avg_usefulness = _mean_numeric_rows(user_review_rows, "usefulness_1to5")
    review_defensive_terms = ("売買非推奨", "実行不可", "実弾不可", "注意報")
    review_defensive_wording_count = sum(
        1 for row in user_review_rows if any(term in str(row.get("subject", "")) for term in review_defensive_terms)
    )

    required_statuses = {key: str(bundle["status"]) for key, bundle in loaded_inputs.items()}
    recommendation_pairs = _daily_proxy_recommendations(
        signal_rows=signal_rows,
        candidate_rows=candidate_rows,
        intraperiod_rows=intraperiod_rows,
        user_review_rows=user_review_rows,
        required_input_statuses=required_statuses,
    )
    recommendation_codes = [code for code, _ in recommendation_pairs]

    lines = [
        "# Daily Proxy Evaluator",
        "",
        "## 1. Safety Boundary",
        "- report-only",
        "- not FORMAL_GO",
        "- no automatic order",
        "- no private/account/order endpoints",
        "- human decides manually",
        "- MEXC raw exports are not imported in this task",
        "",
        "## 2. Input Status",
        f"- report_date: `{resolved_report_date}`",
        f"- lookback_days: `{window_days}`",
        f"- selected_window: `{window_start.isoformat()} -> {window_end.isoformat()}`",
        f"- report_path: `{report_path}`",
        "",
    ]

    for key, bundle in loaded_inputs.items():
        latest_timestamp = ""
        for row in bundle["rows"]:
            raw_timestamp = str(row.get("timestamp_jst", "")).strip()
            dt = _parse_dt(raw_timestamp)
            if dt is None:
                continue
            normalized = dt.astimezone(JST).isoformat()
            if not latest_timestamp or normalized > latest_timestamp:
                latest_timestamp = normalized
        lines.append(
            f"- `{key}`: status={bundle['status']} / rows={bundle['total_rows']} / "
            f"selected_rows={bundle['selected_row_count']} / parse_warning_rows={bundle['parse_warning_rows']}"
            + (f" / latest_timestamp={latest_timestamp}" if latest_timestamp else "")
        )
    lines.append("")

    lines.extend(
        [
            "## 3. Signal Outcome Proxy",
            f"- selected rows: {len(signal_rows)}",
            f"- bias: {_proxy_counter_line(signal_bias_counts)}",
            f"- prelabel: {_proxy_counter_line(signal_prelabel_counts)}",
            f"- direction_outcome: {_proxy_counter_line(signal_direction_counts)}",
            f"- entry_outcome: {_proxy_counter_line(signal_entry_counts)}",
            f"- wait_outcome: {_proxy_counter_line(signal_wait_counts)}",
            f"- skip_outcome: {_proxy_counter_line(signal_skip_counts)}",
            f"- outcome: {_proxy_counter_line(signal_outcome_counts)}",
            f"- skip_too_strict count: {signal_skip_too_strict_count}",
            f"- good_entry count: {signal_good_entry_count}",
            "",
            "## 4. Active Plan Candidate Proxy",
            f"- selected rows: {len(candidate_rows)}",
            f"- side: {_proxy_counter_line(candidate_side_counts)}",
            f"- candidate_type: {_proxy_counter_line(candidate_type_counts)}",
            f"- active_primary_action: {_proxy_counter_line(candidate_action_counts)}",
            f"- candidate_status: {_proxy_counter_line(candidate_status_counts)}",
            f"- outcome_direction_outcome: {_proxy_counter_line(candidate_direction_counts)}",
            f"- tp1_close_reached_24h true count: {candidate_tp1_close_count}",
            f"- sl_close_reached_24h true count: {candidate_sl_close_count}",
            "",
            "## 5. Intraperiod Proxy",
            f"- selected rows: {len(intraperiod_rows)}",
            f"- side: {_proxy_counter_line(intraperiod_side_counts)}",
            f"- candidate_type: {_proxy_counter_line(intraperiod_type_counts)}",
            f"- active_primary_action: {_proxy_counter_line(intraperiod_action_counts)}",
            f"- outcome: {_proxy_counter_line(intraperiod_outcome_counts)}",
            f"- first_exit_reason: {_proxy_counter_line(intraperiod_exit_reason_counts)}",
            f"- tp1_first count: {intraperiod_tp1_count}",
            f"- sl_first count: {intraperiod_sl_count}",
            f"- timeout count: {intraperiod_timeout_count}",
            f"- no_ohlcv count: {intraperiod_no_ohlcv_count}",
            f"- average mfe_r: {intraperiod_mfe_r_avg:.2f}",
            f"- average mae_r: {intraperiod_mae_r_avg:.2f}",
            "",
            "## 6. User Review Proxy",
            f"- selected rows: {len(user_review_rows)}",
            f"- review_status: {_proxy_counter_line(review_status_counts)}",
            f"- user_verdict: {_proxy_counter_line(review_verdict_counts)}",
            f"- would_trade: {_proxy_counter_line(review_would_trade_counts)}",
            f"- review_source: {_proxy_counter_line(review_source_counts)}",
            f"- average usefulness_1to5: {review_avg_usefulness:.2f}",
            f"- defensive wording count: {review_defensive_wording_count}",
            "",
            "## 7. Daily Proxy Recommendations",
        ]
    )

    if recommendation_pairs:
        for code, reason in recommendation_pairs:
            lines.append(f"- `{code}`: {reason} / proxy-only / not trading permission")
    else:
        lines.append("- なし")

    lines.extend(
        [
            "",
            "## 8. Limitations",
            "- no actual human PnL yet",
            "- MEXC raw exports are not imported in this task",
            "- daily proxy is not ground truth",
            "- biweekly actual trade import will calibrate proxy vs actual later",
        ]
    )

    report = "\n".join(lines) + "\n"
    _ensure_parent(report_path)
    report_path.write_text(report, encoding="utf-8")

    payload = {
        "schema_version": "daily_proxy_evaluator.v1",
        "report_date": resolved_report_date,
        "report_path": str(report_path),
        "generated_at_jst": datetime.now(tz=JST).isoformat(),
        "input_counts": {
            key: {
                "status": bundle["status"],
                "rows": bundle["total_rows"],
                "selected_rows": bundle["selected_row_count"],
                "parse_warning_rows": bundle["parse_warning_rows"],
            }
            for key, bundle in loaded_inputs.items()
        },
        "recommendation_codes": recommendation_codes,
        "safety_boundary": "report-only / not FORMAL_GO / no automatic order / no private/account/order endpoints / human decides manually",
    }
    return report, payload


def build_daily_proxy_evaluator_report(
    *,
    base_dir: Path = BASE_DIR,
    output_md: Path | None = None,
    report_date: str | None = None,
    lookback_days: int = 7,
) -> str:
    report, _ = _build_daily_proxy_evaluator_report_data(
        base_dir=base_dir,
        output_md=output_md,
        report_date=report_date,
        lookback_days=lookback_days,
    )
    return report


def _run_summarize_actionability_shadow_decisions_command(
    args: argparse.Namespace,
    parser: argparse.ArgumentParser | None = None,
) -> None:
    output_md_arg = getattr(args, "output_md", None)
    report = build_actionability_shadow_decision_summary(
        input_csv=Path(args.input_csv),
        output_md=Path(output_md_arg) if output_md_arg else None,
        parser=parser,
    )
    if output_md_arg:
        sys.stdout.write(f"actionability_shadow_summary_output_md={output_md_arg}\n")
    else:
        sys.stdout.write(report)


def _load_manual_delivery_input_json_if_exists(path: Path, parser: argparse.ArgumentParser | None = None) -> dict[str, Any]:
    if not path.exists():
        return {}
    return _load_json_object(path, parser)


def _manual_delivery_local_inbox_markdown(
    *,
    input_json_path: Path,
    bundle_dir: Path,
    input_json: dict[str, Any],
    actionability_shadow_output_csv: Path | None = None,
    actionability_shadow_summary_output_md: Path | None = None,
) -> str:
    display_json = dict(input_json)
    if any(key not in display_json for key in ("actionability_label", "actionability_reasons", "human_action", "actionability_safety")):
        display_json.update(
            _compute_actionability_gate_v1(
                active_plan_label=str(display_json.get("active_plan_label", "")),
                source_readiness=_manual_delivery_extract_summary_field(
                    str(display_json.get("intraperiod_evidence_summary", "")),
                    "source_readiness",
                )
                or "unknown",
                pending_caveat=str(display_json.get("pending_caveat", "")),
                side=str(display_json.get("side", "")),
                entry_mode=str(display_json.get("entry_mode", "")),
                tp_plan=str(display_json.get("tp_plan", "")),
                sl_or_invalidation=str(display_json.get("sl_or_invalidation", "")),
                timeout_or_wait_limit=str(display_json.get("timeout_or_wait_limit", "")),
            )
        )
    lines = [
        "# Manual Delivery Local Inbox",
        "",
        "## Safety Status",
        "- report-only",
        "- not FORMAL_GO",
        "- no automatic order",
        "- ACTIVE_* guidance only",
        "- human must decide manually",
        "- no external notification integration",
        "",
        "## Input JSON",
        f"- input_json_path={input_json_path}",
        f"- input_json_exists={str(input_json_path.exists()).lower()}",
    ]
    for key in [
        "generated_at_jst",
        "symbol",
        "timeframe",
        "data_source",
        "data_freshness",
        "detail_report_path",
        "active_plan_label",
        "side",
        "entry_mode",
        "intraperiod_evidence_summary",
        "pending_caveat",
        "actionability_label",
        "actionability_reasons",
        "human_action",
        "actionability_safety",
    ]:
        if key in display_json:
            lines.append(f"- {key}={display_json[key]}")

    lines.extend(
        [
            "",
            "## Bundle Files",
        ]
    )
    for filename in ["subject.txt", "body.txt", "checklist.txt", "package.txt", "README.txt"]:
        bundle_path = bundle_dir / filename
        lines.append(f"- {filename} exists={str(bundle_path.exists()).lower()} path={bundle_path}")

    if actionability_shadow_output_csv is not None:
        lines.extend(
            [
                "",
                "## Actionability Shadow Output",
                f"- actionability_shadow_output_csv={actionability_shadow_output_csv}",
                f"- actionability_shadow_output_csv_exists={str(actionability_shadow_output_csv.exists()).lower()}",
                "- safety=report-only, not FORMAL_GO, no automatic order, human decides manually",
            ]
        )
        if actionability_shadow_summary_output_md is not None:
            lines.extend(
                [
                    f"- actionability_shadow_summary_output_md={actionability_shadow_summary_output_md}",
                    f"- actionability_shadow_summary_output_md_exists={str(actionability_shadow_summary_output_md.exists()).lower()}",
                ]
            )

    lines.extend(
        [
            "",
            "## Human Review Checklist",
            "- confirm JSON was reviewed by a human",
            "- confirm body/package wording is report-only",
            "- confirm not FORMAL_GO is visible",
            "- confirm no automatic order is visible",
            "- confirm pending caveat is visible",
            "- confirm human decides manually",
            "- confirm any send/post/share action is outside repo automation",
            "",
            "## Next Human Action",
            "- inspect the generated local files manually",
            "- optionally copy/paste manually into an external app",
            "- do not treat the inbox as trade approval",
        ]
    )
    return "\n".join(lines) + "\n"


def _run_write_latest_manual_delivery_local_inbox_command(
    args: argparse.Namespace,
    parser: argparse.ArgumentParser | None = None,
) -> None:
    input_json_path = Path(args.input_json)
    try:
        input_json = _load_manual_delivery_input_json_if_exists(input_json_path, parser)
    except (OSError, ValueError):
        raise
    bundle_dir = Path(args.bundle_dir)
    markdown = _manual_delivery_local_inbox_markdown(
        input_json_path=input_json_path,
        bundle_dir=bundle_dir,
        input_json=input_json,
    )
    output_md = Path(args.output_md)
    _ensure_parent(output_md)
    output_md.write_text(markdown, encoding="utf-8")
    sys.stdout.write(f"{output_md}\n")


def _manual_delivery_source_files_lines(
    *,
    base_dir: Path,
    intraperiod_outcomes_path: str,
    detail_report_path: str | None,
    source_stale_after_hours: float,
    reference_jst: datetime | None = None,
) -> list[str]:
    source_state = _manual_delivery_source_readiness_state(
        base_dir=base_dir,
        intraperiod_outcomes_path=intraperiod_outcomes_path,
        detail_report_path=detail_report_path,
        source_stale_after_hours=source_stale_after_hours,
        reference_jst=reference_jst,
    )
    return [
        f"intraperiod_outcomes_path={source_state['intraperiod_outcomes_path']}",
        f"intraperiod_outcomes_exists={source_state['intraperiod_outcomes_exists']}",
        f"detail_report_path={source_state['detail_report_path']}",
        f"detail_report_exists={source_state['detail_report_exists']}",
        f"generated_at_jst={source_state['generated_at_jst']}",
        f"source_stale_after_hours={source_state['source_stale_after_hours']}",
        f"intraperiod_outcomes_mtime_jst={source_state['intraperiod_outcomes_mtime_jst']}",
        f"intraperiod_outcomes_age_minutes={source_state['intraperiod_outcomes_age_minutes']}",
        f"intraperiod_outcomes_freshness={source_state['intraperiod_outcomes_freshness']}",
        f"detail_report_mtime_jst={source_state['detail_report_mtime_jst']}",
        f"detail_report_age_minutes={source_state['detail_report_age_minutes']}",
        f"detail_report_freshness={source_state['detail_report_freshness']}",
        f"source_readiness={source_state['source_readiness']}",
        "safety=report-only_not_FORMAL_GO_no_automatic_order",
    ]


def _manual_delivery_extract_summary_field(summary_text: str, field_name: str) -> str:
    prefix = f"{field_name}="
    for part in str(summary_text).split(";"):
        normalized = part.strip()
        if normalized.startswith(prefix):
            return normalized[len(prefix) :].strip()
    return ""


def _manual_delivery_local_flow_manifest_data(
    *,
    output_dir: Path,
    generated_at_jst: str,
    source_readiness: str,
    actionability_label: str,
    actionability_reasons: list[str],
    human_action: str,
    actionability_safety: str,
    source_files_path: Path,
    input_json_path: Path,
    bundle_dir: Path,
    inbox_path: Path,
    shadow_decision_enabled: bool,
    actionability_shadow_output_csv: Path | None = None,
    actionability_shadow_summary_output_md: Path | None = None,
) -> dict[str, Any]:
    def _artifact_entry(path: Path) -> dict[str, Any]:
        return {"path": str(path), "exists": path.exists()}

    bundle_files = {
        filename: _artifact_entry(bundle_dir / filename)
        for filename in ["subject.txt", "body.txt", "checklist.txt", "package.txt", "README.txt"]
    }
    manifest: dict[str, Any] = {
        "schema_version": "manual_delivery_local_flow.v1",
        "generated_at_jst": generated_at_jst,
        "safety_boundary": "report-only / not FORMAL_GO / no automatic order / human decides manually",
        "output_dir": str(output_dir),
        "source_readiness": source_readiness,
        "actionability_label": actionability_label,
        "actionability_reasons": list(actionability_reasons),
        "human_action": human_action,
        "actionability_safety": actionability_safety,
        "artifacts": {
            "source_files": _artifact_entry(source_files_path),
            "input_json": _artifact_entry(input_json_path),
            "bundle": bundle_files,
            "inbox": _artifact_entry(inbox_path),
        },
        "shadow_decision_enabled": shadow_decision_enabled,
        "actionability_shadow_output_csv": str(actionability_shadow_output_csv) if actionability_shadow_output_csv is not None else "",
        "actionability_shadow_output_csv_exists": bool(actionability_shadow_output_csv and actionability_shadow_output_csv.exists()),
        "actionability_shadow_summary_output_md": (
            str(actionability_shadow_summary_output_md) if actionability_shadow_summary_output_md is not None else ""
        ),
        "actionability_shadow_summary_output_md_exists": bool(
            actionability_shadow_summary_output_md and actionability_shadow_summary_output_md.exists()
        ),
        "paper_positions_integration": False,
        "external_notification_integration": False,
    }
    return manifest


def _manual_delivery_local_flow_manifest_artifact_readiness_counts(
    artifacts: dict[str, Any],
    parser: argparse.ArgumentParser | None = None,
) -> tuple[int, int]:
    existing = 0
    total = 0

    def _visit(node: Any, location: str) -> None:
        nonlocal existing, total
        if isinstance(node, dict) and "path" in node and "exists" in node:
            path_value = node.get("path")
            exists_value = node.get("exists")
            if not isinstance(path_value, str):
                message = f"manifest artifact path must be a string at {location}"
                if parser is None:
                    raise ValueError(message)
                parser.error(message)
            if not isinstance(exists_value, bool):
                message = f"manifest artifact exists must be a boolean at {location}"
                if parser is None:
                    raise ValueError(message)
                parser.error(message)
            total += 1
            if exists_value:
                existing += 1
            return
        if isinstance(node, dict):
            for key, value in node.items():
                child_location = f"{location}.{key}" if location else str(key)
                _visit(value, child_location)
            return
        message = f"manifest artifacts must contain only nested objects or path/exists entries: {location or 'artifacts'}"
        if parser is None:
            raise ValueError(message)
        parser.error(message)

    _visit(artifacts, "artifacts")
    return existing, total


def _load_manual_delivery_local_flow_manifest_json(
    manifest_json: Path,
    parser: argparse.ArgumentParser | None = None,
) -> dict[str, Any]:
    if not manifest_json.exists():
        message = f"manifest_json does not exist: {manifest_json}"
        if parser is None:
            raise FileNotFoundError(message)
        parser.error(message)
    manifest = _load_json_object(manifest_json, parser)
    schema_version = str(manifest.get("schema_version", "")).strip()
    if schema_version != "manual_delivery_local_flow.v1":
        message = f"unsupported manifest schema_version: {schema_version or 'missing'}"
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    required_top_level_keys = [
        "generated_at_jst",
        "safety_boundary",
        "output_dir",
        "source_readiness",
        "actionability_label",
        "actionability_reasons",
        "human_action",
        "actionability_safety",
        "artifacts",
        "shadow_decision_enabled",
        "actionability_shadow_output_csv",
        "actionability_shadow_output_csv_exists",
        "actionability_shadow_summary_output_md",
        "actionability_shadow_summary_output_md_exists",
    ]
    missing_keys = [key for key in required_top_level_keys if key not in manifest]
    if missing_keys:
        message = "manifest missing required keys: " + ", ".join(missing_keys)
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    safety_boundary = str(manifest.get("safety_boundary", "")).strip()
    required_safety_terms = ["report-only", "not FORMAL_GO", "no automatic order", "human decides manually"]
    if not all(term in safety_boundary for term in required_safety_terms):
        message = f'manifest safety_boundary must contain: "{" / ".join(required_safety_terms)}"'
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    if manifest.get("paper_positions_integration") is not False:
        message = "manifest paper_positions_integration must be false"
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    if manifest.get("external_notification_integration") is not False:
        message = "manifest external_notification_integration must be false"
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    artifacts = manifest.get("artifacts")
    if not isinstance(artifacts, dict):
        message = "manifest artifacts must be an object"
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    _manual_delivery_local_flow_manifest_artifact_readiness_counts(artifacts, parser)
    return manifest


def _manual_delivery_local_flow_manifest_summary_markdown(manifest: dict[str, Any], parser: argparse.ArgumentParser | None = None) -> str:
    artifacts = manifest.get("artifacts")
    if not isinstance(artifacts, dict):
        message = "manifest artifacts must be an object"
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    existing_artifacts, total_artifacts = _manual_delivery_local_flow_manifest_artifact_readiness_counts(artifacts, parser)
    lines = [
        "# Manual Delivery Local Flow Manifest Summary",
        "",
        f"- schema_version: {manifest['schema_version']}",
        f"- generated_at_jst: {manifest['generated_at_jst']}",
        f"- output_dir: {manifest['output_dir']}",
        f"- source_readiness: {manifest['source_readiness']}",
        f"- actionability_label: {manifest['actionability_label']}",
        f"- human_action: {manifest['human_action']}",
        f"- shadow_decision_enabled: {str(manifest['shadow_decision_enabled']).lower()}",
        f"- actionability_shadow_output_csv: {manifest['actionability_shadow_output_csv']}",
        f"- actionability_shadow_output_csv_exists: {str(manifest['actionability_shadow_output_csv_exists']).lower()}",
        f"- actionability_shadow_summary_output_md: {manifest['actionability_shadow_summary_output_md']}",
        f"- actionability_shadow_summary_output_md_exists: {str(manifest['actionability_shadow_summary_output_md_exists']).lower()}",
        f"- safety_boundary: {manifest['safety_boundary']}",
        f"- paper_positions_integration: {str(manifest['paper_positions_integration']).lower()}",
        f"- external_notification_integration: {str(manifest['external_notification_integration']).lower()}",
        "",
        "## Artifact Readiness",
        f"- existing/total: {existing_artifacts}/{total_artifacts}",
        "",
    ]
    return "\n".join(lines) + "\n"


def _manual_delivery_local_flow_manifest_review_data(
    manifest: dict[str, Any],
    parser: argparse.ArgumentParser | None = None,
) -> dict[str, Any]:
    artifacts = manifest.get("artifacts")
    if not isinstance(artifacts, dict):
        message = "manifest artifacts must be an object"
        if parser is None:
            raise ValueError(message)
        parser.error(message)
    existing_artifacts, total_artifacts = _manual_delivery_local_flow_manifest_artifact_readiness_counts(artifacts, parser)
    return {
        "schema_version": "manual_delivery_manifest_review.v1",
        "manifest_schema_version": manifest["schema_version"],
        "generated_at_jst": manifest["generated_at_jst"],
        "output_dir": manifest["output_dir"],
        "review_status": "valid_report_only_manifest",
        "human_review_required": True,
        "trade_execution_allowed": False,
        "paper_positions_integration": False,
        "external_notification_integration": False,
        "safety_boundary": manifest["safety_boundary"],
        "source_readiness": manifest["source_readiness"],
        "actionability_label": manifest["actionability_label"],
        "human_action": manifest["human_action"],
        "shadow_decision_enabled": bool(manifest["shadow_decision_enabled"]),
        "artifact_existing_count": existing_artifacts,
        "artifact_total_count": total_artifacts,
        "artifact_readiness": "complete" if existing_artifacts == total_artifacts else "incomplete",
        "actionability_shadow_output_csv": manifest["actionability_shadow_output_csv"],
        "actionability_shadow_output_csv_exists": bool(manifest["actionability_shadow_output_csv_exists"]),
        "actionability_shadow_summary_output_md": manifest["actionability_shadow_summary_output_md"],
        "actionability_shadow_summary_output_md_exists": bool(manifest["actionability_shadow_summary_output_md_exists"]),
    }


def build_manual_delivery_local_flow_manifest_review(
    *,
    manifest_json: Path,
    output_md: Path | None = None,
    output_json: Path | None = None,
    parser: argparse.ArgumentParser | None = None,
) -> tuple[str, dict[str, Any]]:
    manifest = _load_manual_delivery_local_flow_manifest_json(manifest_json, parser)
    report = _manual_delivery_local_flow_manifest_summary_markdown(manifest, parser)
    review_data = _manual_delivery_local_flow_manifest_review_data(manifest, parser)
    if output_md is not None:
        _ensure_parent(output_md)
        output_md.write_text(report, encoding="utf-8")
    if output_json is not None:
        _ensure_parent(output_json)
        output_json.write_text(json.dumps(review_data, ensure_ascii=False, indent=2, sort_keys=True) + "\n", encoding="utf-8")
    return report, review_data


