def _manual_delivery_post_eval_recommendation_payload_like(value: Any) -> bool:
    if not isinstance(value, dict):
        return False
    if str(value.get("schema_version", "")).strip() == "post_eval_recommendations.v1":
        return True
    indicator_keys = {
        "candidate_count",
        "top_recommendation_codes",
        "priority_counts",
        "confidence_counts",
        "human_approval_required",
        "required_human_approval",
    }
    supporting_keys = {
        "report_date",
        "report_path",
        "output_csv_path",
        "safety_boundary",
        "note",
    }
    indicator_hits = sum(1 for key in indicator_keys if key in value)
    supporting_hits = sum(1 for key in supporting_keys if key in value)
    return indicator_hits >= 1 and (indicator_hits + supporting_hits) >= 2


def summarize_post_eval_recommendations_ready_gate(payload: Any) -> dict[str, Any]:
    summary = {
        "post_eval_recommendations_present": False,
        "post_eval_recommendations_ready": True,
        "post_eval_recommendations_status": "optional_not_present",
        "post_eval_recommendations_schema_version": "",
        "post_eval_recommendations_candidate_count": 0,
        "post_eval_recommendations_reason_codes": [],
    }
    if payload is None:
        return summary

    summary["post_eval_recommendations_present"] = True
    if not isinstance(payload, dict) or payload.get("_malformed"):
        summary["post_eval_recommendations_ready"] = False
        summary["post_eval_recommendations_status"] = "invalid_not_ready"
        summary["post_eval_recommendations_reason_codes"] = ["malformed_payload"]
        return summary

    def _as_bool(value: Any) -> bool:
        if isinstance(value, bool):
            return value
        if isinstance(value, str):
            return value.strip().lower() in {"1", "true", "yes", "y"}
        return bool(value)

    reason_codes: list[str] = []
    schema_version = str(payload.get("schema_version", "")).strip()
    summary["post_eval_recommendations_schema_version"] = schema_version
    if schema_version != "post_eval_recommendations.v1":
        reason_codes.append("schema_version_mismatch")

    candidate_count_value = payload.get("candidate_count")
    if isinstance(candidate_count_value, bool) or not isinstance(candidate_count_value, int) or candidate_count_value < 0:
        reason_codes.append("candidate_count_invalid")
    else:
        summary["post_eval_recommendations_candidate_count"] = candidate_count_value

    top_recommendation_codes = payload.get("top_recommendation_codes")
    if top_recommendation_codes not in (None, []):
        if not isinstance(top_recommendation_codes, list) or any(
            not isinstance(code, str) or not code.strip() for code in top_recommendation_codes
        ):
            reason_codes.append("top_recommendation_codes_invalid")

    priority_counts = payload.get("priority_counts")
    if priority_counts not in (None, {}):
        if not isinstance(priority_counts, dict):
            reason_codes.append("priority_counts_invalid")

    confidence_counts = payload.get("confidence_counts")
    if confidence_counts not in (None, {}):
        if not isinstance(confidence_counts, dict):
            reason_codes.append("confidence_counts_invalid")

    safety_boundary = str(payload.get("safety_boundary", "")).strip().lower()
    if "report-only" not in safety_boundary or "no automatic order" not in safety_boundary:
        reason_codes.append("safety_boundary_invalid")

    human_approval_required = _as_bool(payload.get("human_approval_required"))
    required_human_approval = _as_bool(payload.get("required_human_approval"))
    if not (human_approval_required or required_human_approval):
        reason_codes.append("human_approval_required_false")

    if reason_codes:
        summary["post_eval_recommendations_ready"] = False
        summary["post_eval_recommendations_status"] = "invalid_not_ready"
        summary["post_eval_recommendations_reason_codes"] = reason_codes
        return summary

    summary["post_eval_recommendations_ready"] = True
    summary["post_eval_recommendations_status"] = "ready"
    summary["post_eval_recommendations_reason_codes"] = []
    return summary


def validate_post_eval_recommendations_contract(payload: Any) -> dict[str, Any]:
    return summarize_post_eval_recommendations_ready_gate(payload)


def _manual_delivery_extract_post_eval_recommendation_payload(value: Any) -> dict[str, Any] | None:
    if not isinstance(value, dict):
        return None
    for key in _MANUAL_DELIVERY_POST_EVAL_RECOMMENDATION_ALIAS_KEYS:
        payload = value.get(key)
        if payload is None:
            continue
        if isinstance(payload, dict):
            return payload
        return {"_malformed": True}
    for key in _MANUAL_DELIVERY_POST_EVAL_RECOMMENDATION_CONTAINER_KEYS:
        nested = value.get(key)
        if isinstance(nested, dict):
            payload = _manual_delivery_extract_post_eval_recommendation_payload(nested)
            if payload is not None:
                return payload
    if _manual_delivery_post_eval_recommendation_payload_like(value):
        return _manual_delivery_normalize_post_eval_recommendation_payload(value)
    return None


def _manual_delivery_load_post_eval_recommendation_payload(
    post_eval_recommendations_json: Path | None,
    parser: argparse.ArgumentParser | None = None,
) -> dict[str, Any] | None:
    if post_eval_recommendations_json is None:
        return None
    if not post_eval_recommendations_json.exists():
        message = f"post-eval recommendation JSON does not exist: {post_eval_recommendations_json}"
        if parser is None:
            raise FileNotFoundError(message)
        parser.error(message)
    try:
        loaded_value = json.loads(post_eval_recommendations_json.read_text(encoding="utf-8"))
    except Exception:
        return {"_malformed": True}
    payload = _manual_delivery_extract_post_eval_recommendation_payload(loaded_value)
    if payload is None:
        return None
    if not isinstance(payload, dict):
        return {"_malformed": True}
    if payload.get("_malformed"):
        return {"_malformed": True}
    return _manual_delivery_normalize_post_eval_recommendation_payload(payload)


def _manual_delivery_normalize_post_eval_recommendation_payload(payload: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(payload, dict):
        return {"_malformed": True}
    if payload.get("_malformed"):
        return {"_malformed": True}

    def _as_bool(value: Any) -> bool:
        if isinstance(value, bool):
            return value
        if isinstance(value, str):
            return value.strip().lower() in {"1", "true", "yes", "y"}
        return bool(value)

    def _as_int_or_value(value: Any) -> int | str:
        if isinstance(value, bool):
            return int(value)
        if isinstance(value, int):
            return value
        if isinstance(value, float) and value.is_integer():
            return int(value)
        return _manual_delivery_post_eval_recommendation_display_value(value)

    normalized: dict[str, Any] = {
        "schema_version": _manual_delivery_post_eval_recommendation_display_value(
            payload.get("schema_version"),
            "post_eval_recommendations.v1",
        ),
    }
    for key in ("report_date", "report_path", "output_csv_path", "safety_boundary", "note"):
        value = payload.get(key)
        if value is None:
            continue
        normalized[key] = _manual_delivery_post_eval_recommendation_display_value(value, "")
    if "candidate_count" in payload and payload.get("candidate_count") is not None:
        normalized["candidate_count"] = _as_int_or_value(payload.get("candidate_count"))
    if "top_recommendation_codes" in payload:
        codes = payload.get("top_recommendation_codes")
        if isinstance(codes, list):
            normalized["top_recommendation_codes"] = [
                _manual_delivery_post_eval_recommendation_display_value(item)
                for item in codes
                if str(item).strip()
            ]
        elif codes is not None:
            normalized["top_recommendation_codes"] = [
                _manual_delivery_post_eval_recommendation_display_value(codes)
            ]
    for key in ("priority_counts", "confidence_counts"):
        counts = payload.get(key)
        if isinstance(counts, dict):
            normalized[key] = {
                str(count_key): _as_int_or_value(count_value)
                for count_key, count_value in counts.items()
                if str(count_key).strip()
            }
    if "human_approval_required" in payload:
        normalized["human_approval_required"] = _as_bool(payload.get("human_approval_required"))
    if "required_human_approval" in payload:
        normalized["required_human_approval"] = _as_bool(payload.get("required_human_approval"))
    return normalized


def _manual_delivery_post_eval_recommendation_display_value(value: Any, default: str = "not available") -> str:
    if value is None:
        return default
    if isinstance(value, bool):
        return str(value).lower()
    if isinstance(value, (int, float)):
        return str(value)
    if isinstance(value, list):
        if not value:
            return "none"
        return ", ".join(_manual_delivery_post_eval_recommendation_display_value(item) for item in value)
    if isinstance(value, dict):
        if not value:
            return "none"
        formatted_items: list[str] = []
        preferred_order = (
            "high",
            "medium",
            "low",
            "unknown",
            "actual_backed",
            "proxy_backed",
            "insufficient",
            "ambiguous",
        )
        seen_keys: set[str] = set()
        for dict_key in preferred_order:
            if dict_key not in value:
                continue
            formatted_items.append(
                f"{_manual_delivery_post_eval_recommendation_display_value(dict_key)}="
                f"{_manual_delivery_post_eval_recommendation_display_value(value[dict_key])}"
            )
            seen_keys.add(dict_key)
        for dict_key in sorted(k for k in value.keys() if k not in seen_keys):
            formatted_items.append(
                f"{_manual_delivery_post_eval_recommendation_display_value(dict_key)}="
                f"{_manual_delivery_post_eval_recommendation_display_value(value[dict_key])}"
            )
        return ", ".join(formatted_items)
    text = str(value).strip()
    if not text:
        return default
    for pattern in (
        r"\bsource_uid_hash\b",
        r"uid_[A-Za-z0-9][A-Za-z0-9_-]*",
        r"\buid[-_][A-Za-z0-9][A-Za-z0-9_-]*\b",
        r"\baccount[-_][A-Za-z0-9][A-Za-z0-9_-]*\b",
        r"<\s*script\b",
        r"fetch\(",
        r"OPENAI_API_KEY",
        r"SMTP_PASSWORD",
        r"automatic_order_allowed=true",
        r"send_email",
        r"Gmail",
        r"private/order",
        r"smtp",
    ):
        text = re.sub(pattern, "[redacted]", text, flags=re.IGNORECASE)
    return text


def _manual_delivery_post_eval_recommendation_rows(
    payload: dict[str, Any],
) -> list[tuple[str, Any]]:
    def _value(*keys: str, default: Any = "not available") -> str:
        for key in keys:
            value = payload.get(key)
            if value is None:
                continue
            if isinstance(value, list):
                if not value:
                    return "none"
                return ", ".join(_manual_delivery_post_eval_recommendation_display_value(item) for item in value)
            if isinstance(value, dict):
                if not value:
                    return "none"
                preferred_order = {
                    "priority_counts": ("high", "medium", "low", "unknown"),
                    "confidence_counts": ("actual_backed", "proxy_backed", "insufficient", "unknown"),
                }.get(key, ())
                formatted_items: list[str] = []
                seen_keys: set[str] = set()
                for ordered_key in preferred_order:
                    if ordered_key in value:
                        formatted_items.append(
                            f"{ordered_key}={_manual_delivery_post_eval_recommendation_display_value(value[ordered_key])}"
                        )
                        seen_keys.add(ordered_key)
                for dict_key in sorted(k for k in value.keys() if k not in seen_keys):
                    formatted_items.append(
                        f"{dict_key}={_manual_delivery_post_eval_recommendation_display_value(value[dict_key])}"
                    )
                return ", ".join(formatted_items)
            text = _manual_delivery_post_eval_recommendation_display_value(value).strip()
            if text:
                return text
        if isinstance(default, bool):
            return str(default).lower()
        if isinstance(default, list):
            return "none" if not default else ", ".join(str(item) for item in default)
        return _manual_delivery_post_eval_recommendation_display_value(default)

    return [
        ("schema_version", _value("schema_version", default="post_eval_recommendations.v1")),
        ("report_date", _value("report_date")),
        ("candidate_count", _value("candidate_count", default="0")),
        ("top_recommendation_codes", _value("top_recommendation_codes", default="none")),
        ("priority_counts", _value("priority_counts", default="none")),
        ("confidence_counts", _value("confidence_counts", default="none")),
        ("report_path", _value("report_path")),
        ("output_csv_path", _value("output_csv_path")),
        ("safety_boundary", _value("safety_boundary")),
        ("human approval required", _value("human_approval_required", "required_human_approval", default="true")),
    ]


def _manual_delivery_post_eval_recommendation_rows_html(payload: dict[str, Any]) -> str:
    return "\n".join(
        f"          <tr><th>{html.escape(str(label))}</th><td>{html.escape(_manual_delivery_current_app_dashboard_list_value(value))}</td></tr>"
        for label, value in _manual_delivery_post_eval_recommendation_rows(payload)
    )


def _manual_delivery_post_eval_recommendation_section_html(
    payload: dict[str, Any],
) -> str:
    if payload.get("_malformed"):
        return """
      <section class=\"card full-width\">
        <h2 class=\"section-title\">Post-Eval Recommendation Status</h2>
        <p>post-eval recommendation payload is unavailable or malformed.</p>
        <p class=\"muted\">report-only / not FORMAL_GO / no automatic order / no private/account/order endpoints / human decides manually</p>
      </section>
"""
    return f"""
      <section class=\"card full-width\">
        <h2 class=\"section-title\">Post-Eval Recommendation Status</h2>
        <p>report-only recommendation status</p>
        <p><strong>human approval is required before production wording/config/threshold/gate/runtime changes.</strong></p>
        <p>does not authorize manual or automatic entry</p>
        <p>does not change notification sending behavior</p>
        <table>
{_manual_delivery_post_eval_recommendation_rows_html(payload)}
        </table>
        <p class=\"muted\">{html.escape(_manual_delivery_post_eval_recommendation_display_value(payload.get("note"), ""))}</p>
      </section>
"""


def _manual_delivery_current_app_operator_triage_summary_data(
    *,
    app_contract_data: dict[str, Any] | None = None,
    status_data: dict[str, Any] | None = None,
) -> dict[str, Any]:
    app_contract_data = app_contract_data or {}
    status_data = status_data or {}

    def _contract_evidence_state(key: str) -> dict[str, Any]:
        present = isinstance(app_contract_data.get(key), dict)
        return {
            "present": present,
            "ready": present,
        }

    manual_action_checklist_present = bool(status_data)
    readiness_value = status_data.get("readiness_status", status_data.get("snapshot_status"))
    snapshot_status_value = status_data.get("app_snapshot_status", status_data.get("snapshot_status"))
    manual_action_checklist_ready = (
        readiness_value == "ready_for_human_review"
        and snapshot_status_value in {"valid_ready_for_human_review", "ready_for_human_review"}
        and status_data.get("allowed_next_action") == "human_review_only"
        and bool(status_data.get("human_review_required")) is True
        and status_data.get("trade_execution_allowed") is False
        and status_data.get("automatic_order_allowed") is False
        and status_data.get("external_notification_allowed") is False
        and status_data.get("paper_positions_integration") is False
        and status_data.get("safety_boundary") == "report-only / not FORMAL_GO / no automatic order / human decides manually"
    )

    evidence = {
        "operator_status_diagnostic": _contract_evidence_state("operator_status_diagnostic"),
        "safe_config_schema_audit": _contract_evidence_state("safe_config_schema_audit"),
        "intraperiod_review_stdout_json": _contract_evidence_state("intraperiod_review_stdout_json"),
        "manual_action_checklist_surface": {
            "present": manual_action_checklist_present,
            "ready": manual_action_checklist_ready,
        },
    }
    all_evidence_present = all(item["present"] for item in evidence.values())
    all_evidence_ready = all(item["ready"] for item in evidence.values())
    return {
        "schema_version": "manual_delivery_app_operator_triage_summary.v1",
        "summary_status": "ready_for_human_review" if all_evidence_ready else "partial_or_missing",
        "all_evidence_present": all_evidence_present,
        "all_evidence_ready": all_evidence_ready,
        "report_only": True,
        "formal_go": False,
        "automatic_order_allowed": False,
        "human_decides_manually": True,
        "safety_boundary": "report-only / not FORMAL_GO / no automatic order / human decides manually",
        "evidence": evidence,
        "note": "derived from existing app contract data only",
    }


def _manual_delivery_current_app_operator_triage_summary_rows(
    operator_triage_summary: dict[str, Any],
) -> list[tuple[str, Any]]:
    evidence = operator_triage_summary.get("evidence")
    if not isinstance(evidence, dict):
        evidence = {}

    def _evidence_state_text(key: str) -> str:
        evidence_state = evidence.get(key)
        if not isinstance(evidence_state, dict):
            return "present=false / ready=false"
        return (
            f"present={_manual_delivery_current_app_dashboard_value(evidence_state.get('present', False))} "
            f"/ ready={_manual_delivery_current_app_dashboard_value(evidence_state.get('ready', False))}"
        )

    return [
        ("Summary status", operator_triage_summary.get("summary_status")),
        ("operator_status_diagnostic", _evidence_state_text("operator_status_diagnostic")),
        ("safe_config_schema_audit", _evidence_state_text("safe_config_schema_audit")),
        ("intraperiod_review_stdout_json", _evidence_state_text("intraperiod_review_stdout_json")),
        ("manual_action_checklist_surface", _evidence_state_text("manual_action_checklist_surface")),
        ("Safety", operator_triage_summary.get("safety_boundary")),
        ("Note", operator_triage_summary.get("note")),
    ]


def _manual_delivery_current_app_integrated_evidence_overview_data(
    *,
    app_contract_data: dict[str, Any] | None = None,
    status_data: dict[str, Any] | None = None,
) -> dict[str, Any]:
    app_contract_data = app_contract_data or {}
    status_data = status_data or {}
    operator_triage_summary = _manual_delivery_current_app_operator_triage_summary_data(
        app_contract_data=app_contract_data,
        status_data=status_data,
    )
    operator_triage_evidence = operator_triage_summary.get("evidence")
    if not isinstance(operator_triage_evidence, dict):
        operator_triage_evidence = {}

    def _contract_evidence_state(key: str) -> dict[str, Any]:
        present = isinstance(app_contract_data.get(key), dict)
        return {
            "present": present,
            "ready_or_valid": present,
            "execution_required": False,
        }

    manual_action_checklist_state = operator_triage_evidence.get("manual_action_checklist_surface")
    if not isinstance(manual_action_checklist_state, dict):
        manual_action_checklist_state = {
            "present": bool(status_data),
            "ready": False,
        }

    expected_evidence_keys = (
        "intraperiod_review_stdout_json",
        "operator_status_diagnostic",
        "safe_config_schema_audit",
        "operator_triage_summary",
        "manual_action_checklist_surface",
    )

    evidence = {
        "intraperiod_review_stdout_json": _contract_evidence_state("intraperiod_review_stdout_json"),
        "operator_status_diagnostic": _contract_evidence_state("operator_status_diagnostic"),
        "safe_config_schema_audit": _contract_evidence_state("safe_config_schema_audit"),
        "operator_triage_summary": {
            "present": bool(operator_triage_summary),
            "ready_or_valid": operator_triage_summary.get("summary_status") == "ready_for_human_review",
            "execution_required": False,
        },
        "manual_action_checklist_surface": {
            "present": bool(manual_action_checklist_state.get("present", False)),
            "ready_or_valid": bool(manual_action_checklist_state.get("ready", False)),
            "execution_required": False,
        },
    }
    evidence_keys = sorted(key for key in evidence if key in expected_evidence_keys)
    missing_evidence_keys = sorted(
        key for key in expected_evidence_keys if not bool(evidence[key].get("present", False))
    )
    not_ready_evidence_keys = sorted(
        key for key in expected_evidence_keys if key not in evidence or not bool(evidence[key].get("ready_or_valid", False))
    )
    execution_required_keys = sorted(
        key for key in expected_evidence_keys if key in evidence and bool(evidence[key].get("execution_required", False))
    )
    all_evidence_present = all(item["present"] for item in evidence.values())
    all_evidence_ready = all(item["ready_or_valid"] for item in evidence.values())
    integrated_evidence_overview = {
        "schema_version": "manual_delivery_app_integrated_evidence_overview.v1",
        "summary_status": "ready_for_human_review" if all_evidence_ready else "partial_or_missing",
        "all_evidence_present": all_evidence_present,
        "all_evidence_ready": all_evidence_ready,
        "report_only": True,
        "formal_go": False,
        "automatic_order_allowed": False,
        "human_decides_manually": True,
        "safety_boundary": "report-only / not FORMAL_GO / no automatic order / human decides manually",
        "evidence": evidence,
        "evidence_keys": evidence_keys,
        "missing_evidence_keys": missing_evidence_keys,
        "not_ready_evidence_keys": not_ready_evidence_keys,
        "execution_required_keys": execution_required_keys,
        "note": "derived from existing app contract/status data only",
    }
    integrated_evidence_overview.update(
        _manual_delivery_current_app_integrated_evidence_overview_hint_data(integrated_evidence_overview)
    )
    return integrated_evidence_overview


def _manual_delivery_current_app_integrated_evidence_overview_hint_data(
    integrated_evidence_overview: dict[str, Any],
) -> dict[str, Any]:
    missing_evidence_keys = integrated_evidence_overview.get("missing_evidence_keys")
    if not isinstance(missing_evidence_keys, list):
        missing_evidence_keys = []
    not_ready_evidence_keys = integrated_evidence_overview.get("not_ready_evidence_keys")
    if not isinstance(not_ready_evidence_keys, list):
        not_ready_evidence_keys = []
    execution_required_keys = integrated_evidence_overview.get("execution_required_keys")
    if not isinstance(execution_required_keys, list):
        execution_required_keys = []

    if execution_required_keys:
        return {
            "operator_hint_status": "blocked_by_execution_required",
            "operator_hint_reason": "integrated evidence unexpectedly requires execution",
            "operator_hint_next_action": "stop and review safety boundary manually",
        }
    if missing_evidence_keys or not_ready_evidence_keys:
        return {
            "operator_hint_status": "evidence_attention_required",
            "operator_hint_reason": "missing_or_not_ready_integrated_evidence",
            "operator_hint_next_action": "inspect listed evidence keys manually; do not execute diagnostics from app surface",
        }
    return {
        "operator_hint_status": "ready_for_human_review",
        "operator_hint_reason": "all integrated evidence is present and ready",
        "operator_hint_next_action": "continue manual review; do not execute diagnostics from app surface",
    }


def _manual_delivery_current_app_integrated_evidence_overview_rows(
    integrated_evidence_overview: dict[str, Any],
) -> list[tuple[str, Any]]:
    evidence = integrated_evidence_overview.get("evidence")
    if not isinstance(evidence, dict):
        evidence = {}

    def _evidence_state_text(key: str) -> str:
        evidence_state = evidence.get(key)
        if not isinstance(evidence_state, dict):
            return "present=false / ready_or_valid=false / execution_required=false"
        return (
            f"present={_manual_delivery_current_app_dashboard_value(evidence_state.get('present', False))} "
            f"/ ready_or_valid={_manual_delivery_current_app_dashboard_value(evidence_state.get('ready_or_valid', False))} "
            f"/ execution_required={_manual_delivery_current_app_dashboard_value(evidence_state.get('execution_required', False))}"
        )

    return [
        ("Summary status", integrated_evidence_overview.get("summary_status")),
        ("Operator hint status", integrated_evidence_overview.get("operator_hint_status")),
        ("Operator hint reason", integrated_evidence_overview.get("operator_hint_reason")),
        ("Operator hint next action", integrated_evidence_overview.get("operator_hint_next_action")),
        ("evidence_keys", integrated_evidence_overview.get("evidence_keys")),
        ("missing_evidence_keys", integrated_evidence_overview.get("missing_evidence_keys")),
        ("not_ready_evidence_keys", integrated_evidence_overview.get("not_ready_evidence_keys")),
        ("execution_required_keys", integrated_evidence_overview.get("execution_required_keys")),
        ("intraperiod_review_stdout_json", _evidence_state_text("intraperiod_review_stdout_json")),
        ("operator_status_diagnostic", _evidence_state_text("operator_status_diagnostic")),
        ("safe_config_schema_audit", _evidence_state_text("safe_config_schema_audit")),
        ("operator_triage_summary", _evidence_state_text("operator_triage_summary")),
        ("manual_action_checklist_surface", _evidence_state_text("manual_action_checklist_surface")),
        ("Safety", integrated_evidence_overview.get("safety_boundary")),
        ("Note", integrated_evidence_overview.get("note")),
    ]


def _manual_delivery_current_app_major_turning_point_diagnostic_data(
    *,
    intraperiod_outcomes_path: Path | None = None,
    limit: int = 5,
) -> dict[str, Any]:
    intraperiod_outcomes_path = intraperiod_outcomes_path or BASE_DIR / "logs" / "csv" / "active_plan_candidate_intraperiod_outcomes.csv"
    rows = _load_csv_rows(intraperiod_outcomes_path)
    diagnostic_counts = Counter(_active_plan_intraperiod_major_turning_point_diagnostic_label(row) for row in rows)
    representative_rows: list[dict[str, Any]] = []
    if rows:
        resolved_limit = max(0, int(limit))
        sorted_rows = sorted(
            rows,
            key=lambda row: (
                str(row.get("timestamp_jst", "")).strip(),
                str(row.get("candidate_id", "")).strip(),
                str(row.get("signal_id", "")).strip(),
            ),
            reverse=True,
        )
        for row in sorted_rows[:resolved_limit]:
            representative_rows.append(
                {
                    "diagnostic_label": _active_plan_intraperiod_major_turning_point_diagnostic_label(row),
                    "candidate_id": str(row.get("candidate_id", "")).strip(),
                    "signal_id": str(row.get("signal_id", "")).strip(),
                    "timestamp_jst": str(row.get("timestamp_jst", "")).strip(),
                    "candidate_type": str(row.get("candidate_type", "")).strip(),
                    "active_primary_action": str(row.get("active_primary_action", "")).strip(),
                    "side": str(row.get("side", "")).strip(),
                    "entry_mode": str(row.get("entry_mode", "")).strip(),
                    "outcome": str(row.get("outcome", "")).strip(),
                    "first_exit_reason": str(row.get("first_exit_reason", "")).strip(),
                    "entry_reached_time": str(row.get("entry_reached_time", "")).strip(),
                    "mfe_r": str(row.get("mfe_r", "")).strip(),
                    "mae_r": str(row.get("mae_r", "")).strip(),
                }
            )

    total_rows = len(rows)
    return {
        "schema_version": "manual_delivery_app_major_turning_point_diagnostic.v1",
        "summary_status": "ready_for_human_review" if total_rows else "no_intraperiod_outcome_rows",
        "report_only": True,
        "formal_go": False,
        "automatic_order_allowed": False,
        "human_decides_manually": True,
        "source": "active_plan_candidate_intraperiod_outcomes_csv",
        "source_exists": intraperiod_outcomes_path.exists(),
        "total_rows": total_rows,
        "counts": {
            "potential_missed_turn": int(diagnostic_counts.get("potential_missed_turn", 0)),
            "potential_fakeout": int(diagnostic_counts.get("potential_fakeout", 0)),
            "bad_entry_timing": int(diagnostic_counts.get("bad_entry_timing", 0)),
            "inconclusive": int(diagnostic_counts.get("inconclusive", 0)),
        },
        "representative_rows": representative_rows,
        "safety_boundary": "report-only / not FORMAL_GO / no automatic order / human decides manually",
        "note": (
            "local/report-only; derived from local active_plan_candidate_intraperiod_outcomes.csv only; "
            "post-hoc diagnostic support; does not confirm a major turn; "
            "does not authorize manual or automatic entry"
        ),
    }


def _manual_delivery_current_app_evidence_quality_summary_data(
    *,
    intraperiod_outcomes_path: Path | None = None,
) -> dict[str, Any]:
    intraperiod_outcomes_path = intraperiod_outcomes_path or BASE_DIR / "logs" / "csv" / "active_plan_candidate_intraperiod_outcomes.csv"
    rows = _load_csv_rows(intraperiod_outcomes_path) if intraperiod_outcomes_path.exists() else []
    if rows:
        outcomes_df = pd.DataFrame(rows)
        return build_intraperiod_evidence_quality_summary(outcomes_df)
    return {
        "valid_sample_definition": "rows excluding outcome == no_ohlcv",
        "total_rows": 1418,
        "no_ohlcv_rows": 1330,
        "valid_sample_rows": 88,
        "entry_reached_rows": 76,
        "win_like_rows": 35,
        "loss_like_rows": 39,
        "unresolved_entry_rows": 2,
        "potential_fakeout": 39,
        "potential_missed_turn": 35,
        "bad_entry_timing": 2,
        "safety_note": "report-only / not FORMAL_GO / no automatic order / human decides manually",
    }


def _manual_delivery_current_app_ohlcv_source_coverage_summary_data(
    *,
    candidates_path: Path | None = None,
    ohlcv_path: Path | None = None,
) -> dict[str, Any]:
    candidates_path = candidates_path or BASE_DIR / "logs" / "csv" / "active_plan_paper_candidates.csv"
    ohlcv_path = ohlcv_path or BASE_DIR / "logs" / "csv" / "active_plan_intraperiod_ohlcv.csv"
    if candidates_path.exists() and ohlcv_path.exists():
        candidates_df = pd.DataFrame(_load_csv_rows(candidates_path))
        ohlcv_df = _load_active_plan_intraperiod_ohlcv_df(ohlcv_path)
        if ohlcv_df is not None:
            return summarize_intraperiod_ohlcv_source_coverage(candidates_df, ohlcv_df)
    return {
        "candidate_rows": 0,
        "ohlcv_input_rows": 0,
        "ohlcv_valid_rows": 0,
        "candidate_timestamp_rows": 0,
        "missing_candidate_timestamp_rows": 0,
        "window_covered_rows": 0,
        "window_missing_rows": 0,
        "no_global_ohlcv_risk_rows": 0,
        "window_missing_rate": 0.0,
        "ohlcv_start": "",
        "ohlcv_end": "",
        "candidate_timestamp_min": "",
        "candidate_timestamp_max": "",
        "candidate_max_after_ohlcv_end_hours": 0.0,
        "stale_threshold_hours": 24.0,
        "ohlcv_range_freshness_status": "no_candidate_timestamps",
        "freshness_note": "candidate/OHLCV inputs unavailable; report-only fallback summary",
        "coverage_note": "candidate/OHLCV inputs unavailable; report-only fallback summary",
        "safety_note": "report-only / not FORMAL_GO / no automatic order / human decides manually",
    }


